/* ============================================================
   Sentence Practice Data — Part 1
   Conjunctions and Compound/Complex Sentences
   For PTE Academic Exam Preparation
   ============================================================ */

var SENTENCE_PRACTICE_1 = {

  coordinatingConjunctions: {
    title: "Coordinating Conjunctions (FANBOYS)",
    theory: "Coordinating conjunctions (For, And, Nor, But, Or, Yet, So) join words, phrases, or independent clauses of equal grammatical rank. When joining two independent clauses, place a comma before the conjunction.",
    exercises: [
      {id:"cc001",type:"fill",q:"Education is important, ___ it empowers individuals to make informed decisions.",a:"for",exp:"'For' means 'because' when used as a coordinating conjunction between two independent clauses."},
      {id:"cc002",type:"fill",q:"The university offers scholarships, ___ many students still struggle with tuition fees.",a:"but",exp:"'But' shows contrast between the two independent clauses."},
      {id:"cc003",type:"fill",q:"Students can study online, ___ they can attend classes in person.",a:"or",exp:"'Or' presents an alternative or choice between two options."},
      {id:"cc004",type:"fill",q:"The government increased funding, ___ new schools were built across the region.",a:"so",exp:"'So' indicates a result or consequence of the first clause."},
      {id:"cc005",type:"fill",q:"Technology improves communication, ___ it also creates new job opportunities.",a:"and",exp:"'And' adds information and joins two related independent clauses."},
      {id:"cc006",type:"fill",q:"The research was not funded, ___ was it approved by the ethics committee.",a:"nor",exp:"'Nor' joins two negative statements. The second clause uses inverted word order (was it)."},
      {id:"cc007",type:"fill",q:"The policy seems effective, ___ its long-term impact remains uncertain.",a:"yet",exp:"'Yet' shows contrast or surprise, similar to 'but' with a stronger sense of unexpectedness."},
      {id:"cc008",type:"fill",q:"Air pollution has decreased in some cities, ___ water contamination continues to rise.",a:"yet",exp:"'Yet' highlights an unexpected contrast between improvements in air quality and worsening water quality."},
      {id:"cc009",type:"fill",q:"Renewable energy reduces emissions, ___ it lowers long-term energy costs.",a:"and",exp:"'And' connects two positive outcomes of renewable energy."},
      {id:"cc010",type:"fill",q:"Healthcare workers face burnout, ___ hospital staffing shortages make the problem worse.",a:"and",exp:"'And' adds a related point about healthcare challenges."},
      {id:"cc011",type:"fill",q:"The experiment failed, ___ the researchers redesigned their methodology.",a:"so",exp:"'So' shows the consequence: the failure led to a redesign."},
      {id:"cc012",type:"fill",q:"Citizens must pay taxes, ___ public services cannot be maintained.",a:"or",exp:"'Or' presents the alternative consequence if taxes are not paid."},
      {id:"cc013",type:"fill",q:"The vaccine was effective, ___ distribution remained a significant challenge.",a:"but",exp:"'But' contrasts the vaccine's effectiveness with distribution difficulties."},
      {id:"cc014",type:"fill",q:"The teacher explained the concept clearly, ___ the students understood it immediately.",a:"so",exp:"'So' shows result: clear explanation led to immediate understanding."},
      {id:"cc015",type:"fill",q:"Deforestation threatens biodiversity, ___ it accelerates climate change.",a:"and",exp:"'And' joins two negative effects of deforestation."},
      {id:"cc016",type:"fill",q:"The study did not include children, ___ did it account for regional differences.",a:"nor",exp:"'Nor' connects two things the study failed to do. Note the inverted word order after 'nor'."},
      {id:"cc017",type:"fill",q:"Many graduates seek employment abroad, ___ domestic job markets cannot absorb them all.",a:"for",exp:"'For' explains the reason graduates look overseas: the domestic market is saturated."},
      {id:"cc018",type:"fill",q:"The organisation promoted healthy eating, ___ obesity rates continued to climb.",a:"yet",exp:"'Yet' signals an unexpected outcome despite the organisation's efforts."},
      {id:"cc019",type:"fill",q:"Students must submit assignments on time, ___ they will receive a penalty.",a:"or",exp:"'Or' warns of the consequence of not meeting the deadline."},
      {id:"cc020",type:"fill",q:"The programme was expensive, ___ the government decided to continue funding it.",a:"but",exp:"'But' contrasts the high cost with the decision to keep funding."},
      {id:"cc021",type:"fill",q:"Urban populations are growing rapidly, ___ infrastructure development has not kept pace.",a:"but",exp:"'But' highlights the gap between population growth and infrastructure."},
      {id:"cc022",type:"fill",q:"The data was analysed carefully, ___ the results were published in a leading journal.",a:"and",exp:"'And' connects two sequential actions in the research process."},
      {id:"cc023",type:"fill",q:"Governments must address inequality, ___ social unrest may intensify.",a:"or",exp:"'Or' presents the negative consequence of failing to address inequality."},
      {id:"cc024",type:"fill",q:"The curriculum was updated, ___ teaching methods remained outdated.",a:"yet",exp:"'Yet' shows the surprising contrast between an updated curriculum and old teaching methods."},
      {id:"cc025",type:"fill",q:"Automation increases efficiency, ___ it reduces the need for manual labour.",a:"and",exp:"'And' adds a second effect of automation."},
      {id:"cc026",type:"fill",q:"The patient did not respond to medication, ___ did the condition improve with therapy.",a:"nor",exp:"'Nor' connects two negative outcomes. Inverted word order follows 'nor'."},
      {id:"cc027",type:"fill",q:"Recycling programmes reduce waste, ___ they conserve valuable natural resources.",a:"and",exp:"'And' joins two benefits of recycling programmes."},
      {id:"cc028",type:"fill",q:"The country faced economic recession, ___ the government implemented austerity measures.",a:"so",exp:"'So' shows the government's response as a result of the recession."},
      {id:"cc029",type:"fill",q:"Online learning offers flexibility, ___ it may lead to social isolation.",a:"but",exp:"'But' introduces a disadvantage that contrasts with the benefit."},
      {id:"cc030",type:"fill",q:"Researchers must obtain consent, ___ their studies will not receive ethical approval.",a:"or",exp:"'Or' warns of the consequence of not obtaining consent."},
      {id:"cc031",type:"fill",q:"The hospital lacked resources, ___ many patients were transferred to other facilities.",a:"so",exp:"'So' indicates the result of the resource shortage."},
      {id:"cc032",type:"fill",q:"Public transport is affordable, ___ many commuters still prefer driving.",a:"yet",exp:"'Yet' highlights the unexpected preference for driving despite affordable public transport."},
      {id:"cc033",type:"fill",q:"The government raised taxes, ___ it needed to fund the new healthcare programme.",a:"for",exp:"'For' explains the reason behind the tax increase."},
      {id:"cc034",type:"fill",q:"Urbanisation creates economic opportunities, ___ it also places pressure on housing markets.",a:"but",exp:"'But' contrasts the economic benefits with housing market pressure."},
      {id:"cc035",type:"fill",q:"The evidence was inconclusive, ___ further research was recommended.",a:"so",exp:"'So' shows the recommendation as a consequence of inconclusive evidence."},
      {id:"cc036",type:"mc",q:"Which sentence correctly uses a coordinating conjunction?",options:["The economy is growing, but unemployment remains high.","The economy is growing but, unemployment remains high.","The economy is growing. But unemployment remains high.","The economy is growing, but, unemployment remains high."],a:0,exp:"When joining two independent clauses, place a comma before the coordinating conjunction, not after it."},
      {id:"cc037",type:"mc",q:"Identify the coordinating conjunction in: 'The study was comprehensive, yet the conclusions were disputed.'",options:["yet","the","was","were"],a:0,exp:"'Yet' is one of the FANBOYS coordinating conjunctions, showing contrast."},
      {id:"cc038",type:"mc",q:"Which FANBOYS conjunction shows cause or reason?",options:["for","so","but","and"],a:0,exp:"'For' means 'because' and explains the reason for the first clause."},
      {id:"cc039",type:"mc",q:"What punctuation is needed before a coordinating conjunction joining two independent clauses?",options:["A comma","A semicolon","A colon","No punctuation"],a:0,exp:"A comma is placed before the coordinating conjunction when it joins two independent clauses."},
      {id:"cc040",type:"mc",q:"Which sentence has a comma splice error?",options:["Pollution is increasing, it harms public health.","Pollution is increasing, and it harms public health.","Pollution is increasing, but regulations are helping.","Pollution is increasing, so action is needed."],a:0,exp:"A comma splice occurs when two independent clauses are joined by just a comma without a conjunction."},
      {id:"cc041",type:"mc",q:"In 'She studied hard, so she passed the exam', what does 'so' indicate?",options:["Result","Contrast","Addition","Reason"],a:0,exp:"'So' as a coordinating conjunction indicates result or consequence."},
      {id:"cc042",type:"mc",q:"Which conjunction best fills the blank: 'The city invested in public parks, ___ residents' well-being improved significantly.'",options:["and","but","or","nor"],a:0,exp:"'And' adds a related positive outcome to the investment in parks."},
      {id:"cc043",type:"mc",q:"Which is NOT a coordinating conjunction?",options:["because","for","and","but"],a:0,exp:"'Because' is a subordinating conjunction. The seven coordinating conjunctions are For, And, Nor, But, Or, Yet, So."},
      {id:"cc044",type:"mc",q:"What is wrong with: 'The report was detailed nor did it include recommendations.'?",options:["Missing comma before 'nor'","'Nor' should be 'and'","The first clause should be negative","Both A and C"],a:3,exp:"'Nor' requires a negative first clause (e.g., 'was not detailed') and a comma before 'nor'."},
      {id:"cc045",type:"mc",q:"Choose the correct sentence:",options:["Climate change is real, and governments must act.","Climate change is real and, governments must act.","Climate change is real, and, governments must act.","Climate change is real and governments, must act."],a:0,exp:"Comma goes before the conjunction 'and' when joining two independent clauses. No comma after the conjunction."},
      {id:"cc046",type:"mc",q:"Which conjunction expresses an unexpected contrast?",options:["yet","and","so","for"],a:0,exp:"'Yet' signals a surprising or unexpected contrast between two clauses."},
      {id:"cc047",type:"mc",q:"In 'He did not attend the lecture, nor did he submit the assignment', why is the word order inverted after 'nor'?",options:["'Nor' requires subject-auxiliary inversion","It is a question","It uses passive voice","'Nor' is a subordinating conjunction"],a:0,exp:"After 'nor', the auxiliary verb comes before the subject (inverted order), similar to question formation."},
      {id:"cc048",type:"mc",q:"Which sentence correctly omits the comma?",options:["She likes tea and coffee.","She likes tea, and coffee.","She went home, and slept.","He ate, and drank water."],a:0,exp:"No comma is needed when 'and' joins two words or phrases (not two independent clauses)."},
      {id:"cc049",type:"mc",q:"Choose the best conjunction: 'The factory must reduce emissions, ___ it will face heavy fines.'",options:["or","and","but","for"],a:0,exp:"'Or' presents the alternative consequence (fines) if emissions are not reduced."},
      {id:"cc050",type:"mc",q:"What type of error is this: 'The population is ageing therefore healthcare costs are rising.'?",options:["Run-on sentence (missing punctuation)","Fragment","Comma splice","Dangling modifier"],a:0,exp:"Two independent clauses are fused without any punctuation or conjunction. 'Therefore' is not a coordinating conjunction."},
      {id:"cc051",type:"mc",q:"Which pair of clauses can be joined with 'for'?",options:["The school closed early, ___ a severe storm was approaching.","The school closed early, ___ the students went home.","The school closed early, ___ the storm had passed.","The school closed early, ___ it reopened the next day."],a:0,exp:"'For' gives the reason (a severe storm) for the first clause (school closing early)."},
      {id:"cc052",type:"mc",q:"How many coordinating conjunctions are there in English?",options:["7","5","6","8"],a:0,exp:"There are exactly seven coordinating conjunctions: For, And, Nor, But, Or, Yet, So (FANBOYS)."},
      {id:"cc053",type:"mc",q:"Which sentence uses 'so' correctly as a coordinating conjunction?",options:["The evidence was strong, so the jury reached a verdict quickly.","So the evidence was strong, the jury reached a verdict.","The evidence was so strong the jury reached a verdict.","The evidence, so strong, the jury reached a verdict."],a:0,exp:"'So' as a coordinating conjunction sits between two independent clauses with a comma before it."},
      {id:"cc054",type:"mc",q:"Choose the correct revision of: 'Technology advances rapidly, society must adapt.'",options:["Technology advances rapidly, so society must adapt.","Technology advances rapidly society must adapt.","Technology advances rapidly, society, must adapt.","Technology advances rapidly so, society must adapt."],a:0,exp:"The original is a comma splice. Adding the conjunction 'so' between the clauses fixes it."},
      {id:"cc055",type:"mc",q:"What does 'nor' indicate?",options:["An additional negative idea","A positive addition","A result","A reason"],a:0,exp:"'Nor' connects a second negative idea to a first negative statement."},
      {id:"cc056",type:"mc",q:"Which sentence needs a comma?",options:["The government promised reform but failed to deliver.","The city grew and the infrastructure could not cope.","She studied hard and passed.","He reads books or watches documentaries."],a:1,exp:"'The city grew' and 'the infrastructure could not cope' are both independent clauses, so a comma is needed before 'and'."},
      {id:"cc057",type:"mc",q:"'The hospital was underfunded, ___ patient outcomes suffered.' Which conjunction best fits?",options:["so","but","or","nor"],a:0,exp:"'So' shows the result: underfunding led to poor patient outcomes."},
      {id:"cc058",type:"mc",q:"Which is a compound sentence?",options:["The teacher explained the theory, and the students took notes.","The teacher who explained the theory was experienced.","Because the teacher explained the theory, students understood.","The experienced teacher explained the theory clearly."],a:0,exp:"A compound sentence has two independent clauses joined by a comma + coordinating conjunction."},
      {id:"cc059",type:"mc",q:"What error does this sentence contain: 'She studied hard, she passed the exam.'?",options:["Comma splice","Run-on sentence","Fragment","No error"],a:0,exp:"Two independent clauses joined only by a comma is a comma splice. Add a conjunction: 'She studied hard, so she passed.'"},
      {id:"cc060",type:"mc",q:"Which revision correctly fixes: 'The environment is deteriorating we must take action.'?",options:["The environment is deteriorating, so we must take action.","The environment is deteriorating, we must take action.","The environment is deteriorating we, must take action.","The environment, is deteriorating, we must take action."],a:0,exp:"Adding a comma and the conjunction 'so' correctly joins the two independent clauses."},
      {id:"cc061",type:"mc",q:"In academic writing, which conjunction is most formal for giving a reason?",options:["for","so","and","but"],a:0,exp:"'For' as a conjunction meaning 'because' is considered more formal and literary than 'so'."},
      {id:"cc062",type:"mc",q:"Which sentence uses 'and' to join phrases (not clauses)?",options:["Research and innovation drive economic growth.","Research is essential, and innovation drives growth.","The study was published, and the results were shared.","Researchers gathered data, and they analysed the results."],a:0,exp:"In 'Research and innovation drive economic growth', 'and' joins two noun phrases sharing the same verb."},
      {id:"cc063",type:"mc",q:"Which conjunction signals an alternative or warning?",options:["or","and","for","nor"],a:0,exp:"'Or' presents an alternative, choice, or warning about a consequence."},
      {id:"cc064",type:"mc",q:"What is the function of the comma in: 'The budget was approved, but several members objected.'?",options:["It separates two independent clauses before a conjunction.","It introduces a list.","It follows an introductory phrase.","It sets off a nonessential element."],a:0,exp:"When a coordinating conjunction joins two independent clauses, a comma precedes the conjunction."},
      {id:"cc065",type:"mc",q:"'He neither attended the meeting ___ replied to the email.' What word completes this?",options:["nor","or","and","but"],a:0,exp:"'Neither...nor' is a correlative conjunction pair. 'Nor' completes 'neither'."},
      {id:"cc066",type:"error",q:"The government invested heavily in education but the results were disappointing.",a:"The government invested heavily in education, but the results were disappointing.",exp:"A comma is needed before 'but' when it joins two independent clauses."},
      {id:"cc067",type:"error",q:"Pollution levels have risen, and affecting public health across the region.",a:"Pollution levels have risen, and this is affecting public health across the region.",exp:"The second clause needs its own subject and verb to be an independent clause. 'Affecting' alone is not a complete clause."},
      {id:"cc068",type:"error",q:"The research was thorough, it provided valuable insights.",a:"The research was thorough, and it provided valuable insights.",exp:"This is a comma splice. Adding the conjunction 'and' between the clauses fixes the error."},
      {id:"cc069",type:"error",q:"Although the economy grew, but unemployment remained high.",a:"The economy grew, but unemployment remained high.",exp:"Do not use 'although' and 'but' together. Choose one: either 'Although the economy grew, unemployment remained high' or 'The economy grew, but unemployment remained high.'"},
      {id:"cc070",type:"error",q:"Students must complete the assignment, or, they will fail the course.",a:"Students must complete the assignment, or they will fail the course.",exp:"No comma should be placed after the coordinating conjunction 'or'."},
      {id:"cc071",type:"error",q:"The data was collected the researchers analysed it carefully.",a:"The data was collected, and the researchers analysed it carefully.",exp:"This is a run-on sentence. Two independent clauses need a comma + conjunction."},
      {id:"cc072",type:"error",q:"Technology has advanced rapidly, yet, many communities still lack internet access.",a:"Technology has advanced rapidly, yet many communities still lack internet access.",exp:"No comma should appear after the coordinating conjunction 'yet'."},
      {id:"cc073",type:"error",q:"Healthcare spending increased so life expectancy improved.",a:"Healthcare spending increased, so life expectancy improved.",exp:"A comma is needed before 'so' when it joins two independent clauses."},
      {id:"cc074",type:"error",q:"The city did not invest in public transport, nor it built new cycling paths.",a:"The city did not invest in public transport, nor did it build new cycling paths.",exp:"After 'nor', the word order must be inverted: auxiliary verb before subject (nor did it build)."},
      {id:"cc075",type:"error",q:"Climate change is a serious issue, for, future generations will suffer the consequences.",a:"Climate change is a serious issue, for future generations will suffer the consequences.",exp:"No comma should follow the coordinating conjunction 'for'."},
      {id:"cc076",type:"error",q:"The programme improved literacy rates, and, it also reduced dropout rates.",a:"The programme improved literacy rates, and it also reduced dropout rates.",exp:"No comma should be placed after the coordinating conjunction 'and'."},
      {id:"cc077",type:"error",q:"The students studied hard they passed the exam.",a:"The students studied hard, so they passed the exam.",exp:"This is a run-on sentence. A comma and the conjunction 'so' (showing result) fix the error."},
      {id:"cc078",type:"error",q:"The hospital was overcrowded, nurses were exhausted, patients waited for hours.",a:"The hospital was overcrowded, nurses were exhausted, and patients waited for hours.",exp:"When listing three independent clauses, use a conjunction before the last one."},
      {id:"cc079",type:"error",q:"Environmental regulations are necessary for they protect ecosystems.",a:"Environmental regulations are necessary, for they protect ecosystems.",exp:"A comma is needed before 'for' when it is used as a coordinating conjunction between two independent clauses."},
      {id:"cc080",type:"error",q:"The policy was unpopular but, the government implemented it regardless.",a:"The policy was unpopular, but the government implemented it regardless.",exp:"The comma goes before 'but', not after it, when joining two independent clauses."},
      {id:"cc081",type:"error",q:"She did not attend the lecture nor she completed the reading.",a:"She did not attend the lecture, nor did she complete the reading.",exp:"'Nor' requires a comma before it and subject-auxiliary inversion after it."},
      {id:"cc082",type:"error",q:"Renewable energy is clean, so affordable for many households.",a:"Renewable energy is clean and affordable for many households.",exp:"'So' cannot join an adjective to a clause this way. Use 'and' to join two adjectives."},
      {id:"cc083",type:"error",q:"Urban sprawl increases commute times it also contributes to air pollution.",a:"Urban sprawl increases commute times, and it also contributes to air pollution.",exp:"Run-on sentence fixed by adding a comma and the conjunction 'and' between the two clauses."},
      {id:"cc084",type:"error",q:"Although the treatment was expensive, but the patient recovered fully.",a:"The treatment was expensive, but the patient recovered fully.",exp:"'Although' and 'but' cannot be used together. Remove 'although' to keep the compound sentence with 'but'."},
      {id:"cc085",type:"error",q:"The government raised taxes, and so many citizens protested.",a:"The government raised taxes, so many citizens protested.",exp:"Do not use 'and so' together as coordinating conjunctions. Use 'so' alone to show result."},
      {id:"cc086",type:"error",q:"Education funding has increased but student performance has not improved.",a:"Education funding has increased, but student performance has not improved.",exp:"A comma is required before 'but' when joining two independent clauses."},
      {id:"cc087",type:"error",q:"The trial was not successful, nor the participants reported any side effects.",a:"The trial was not successful, nor did the participants report any side effects.",exp:"After 'nor', use inverted word order: 'nor did the participants report'."},
      {id:"cc088",type:"error",q:"The university expanded its campus, yet it did not hired more staff.",a:"The university expanded its campus, yet it did not hire more staff.",exp:"After 'did not', use the base form of the verb: 'hire', not 'hired'."},
      {id:"cc089",type:"error",q:"Recycling saves resources, it also reduces landfill waste.",a:"Recycling saves resources, and it also reduces landfill waste.",exp:"Comma splice fixed by adding the coordinating conjunction 'and'."},
      {id:"cc090",type:"error",q:"The experiment took three years to complete, and also requiring significant funding.",a:"The experiment took three years to complete and also required significant funding.",exp:"The second part should be a parallel verb ('required') matching 'took', not a participle phrase."},
      {id:"cc091",type:"combine",q:"The government implemented new policies. The economy began to recover.",a:"The government implemented new policies, and the economy began to recover.",exp:"'And' joins two related events. A comma goes before the conjunction."},
      {id:"cc092",type:"combine",q:"Solar energy is renewable. It requires significant initial investment.",a:"Solar energy is renewable, but it requires significant initial investment.",exp:"'But' shows contrast between the benefit and the cost."},
      {id:"cc093",type:"combine",q:"Schools must update their curricula. Students will not be prepared for the modern workforce.",a:"Schools must update their curricula, or students will not be prepared for the modern workforce.",exp:"'Or' presents the negative consequence of inaction."},
      {id:"cc094",type:"combine",q:"The research findings were significant. They were published in a prestigious journal.",a:"The research findings were significant, so they were published in a prestigious journal.",exp:"'So' shows the result: significance led to prestigious publication."},
      {id:"cc095",type:"combine",q:"The city banned single-use plastics. Waste reduction targets were met within a year.",a:"The city banned single-use plastics, and waste reduction targets were met within a year.",exp:"'And' connects the action to its positive outcome."},
      {id:"cc096",type:"combine",q:"The vaccine was distributed widely. Infection rates did not decrease as expected.",a:"The vaccine was distributed widely, yet infection rates did not decrease as expected.",exp:"'Yet' shows the unexpected outcome despite wide distribution."},
      {id:"cc097",type:"combine",q:"Citizens must conserve water. The reservoir will run dry before winter.",a:"Citizens must conserve water, or the reservoir will run dry before winter.",exp:"'Or' warns of the consequence if conservation does not happen."},
      {id:"cc098",type:"combine",q:"The new regulation was controversial. It was necessary to protect public health.",a:"The new regulation was controversial, but it was necessary to protect public health.",exp:"'But' contrasts the controversy with the necessity."},
      {id:"cc099",type:"combine",q:"Unemployment has risen sharply. Many families are struggling to pay their bills.",a:"Unemployment has risen sharply, so many families are struggling to pay their bills.",exp:"'So' links the cause (unemployment) to the effect (financial struggles)."},
      {id:"cc100",type:"combine",q:"The professor did not respond to the email. She did not attend the meeting.",a:"The professor did not respond to the email, nor did she attend the meeting.",exp:"'Nor' connects two negative statements. Inverted word order follows 'nor'."},
      {id:"cc101",type:"combine",q:"Air quality has improved. Residents report fewer respiratory problems.",a:"Air quality has improved, and residents report fewer respiratory problems.",exp:"'And' connects the improvement to its positive result."},
      {id:"cc102",type:"combine",q:"The policy has broad public support. Several key stakeholders oppose it.",a:"The policy has broad public support, yet several key stakeholders oppose it.",exp:"'Yet' highlights the unexpected opposition despite broad support."},
      {id:"cc103",type:"combine",q:"The project was delayed significantly. The budget was doubled to compensate.",a:"The project was delayed significantly, so the budget was doubled to compensate.",exp:"'So' shows the consequence of the delay."},
      {id:"cc104",type:"combine",q:"Students can complete the test at home. They can take it in the examination centre.",a:"Students can complete the test at home, or they can take it in the examination centre.",exp:"'Or' presents two alternative options."},
      {id:"cc105",type:"combine",q:"The company invests heavily in training. Employee retention rates are high.",a:"The company invests heavily in training, so employee retention rates are high.",exp:"'So' shows that high retention is the result of heavy investment in training."},
      {id:"cc106",type:"combine",q:"Biodiversity is declining rapidly. Conservation efforts remain underfunded.",a:"Biodiversity is declining rapidly, and conservation efforts remain underfunded.",exp:"'And' adds a second concerning fact about the environmental situation."},
      {id:"cc107",type:"combine",q:"Taxes were increased to fund healthcare. Many citizens supported the decision.",a:"Taxes were increased to fund healthcare, and many citizens supported the decision.",exp:"'And' adds the public response to the tax increase."},
      {id:"cc108",type:"combine",q:"The study had methodological flaws. The conclusions were still considered valid.",a:"The study had methodological flaws, but the conclusions were still considered valid.",exp:"'But' contrasts the flaws with the validity of conclusions."},
      {id:"cc109",type:"combine",q:"Governments must invest in education. Economic growth will stagnate.",a:"Governments must invest in education, or economic growth will stagnate.",exp:"'Or' warns of the consequence of not investing in education."},
      {id:"cc110",type:"combine",q:"The hospital did not have enough ventilators. It did not have sufficient staff.",a:"The hospital did not have enough ventilators, nor did it have sufficient staff.",exp:"'Nor' joins two negative facts. Inverted word order follows 'nor'."},
      {id:"cc111",type:"identify",q:"Education is essential, and it promotes social mobility.",a:"and (addition)",exp:"'And' is a coordinating conjunction that adds information."},
      {id:"cc112",type:"identify",q:"The city invested in infrastructure, yet traffic congestion worsened.",a:"yet (contrast)",exp:"'Yet' is a coordinating conjunction showing unexpected contrast."},
      {id:"cc113",type:"identify",q:"Researchers must publish their findings, or they risk losing funding.",a:"or (alternative/warning)",exp:"'Or' is a coordinating conjunction presenting an alternative or consequence."},
      {id:"cc114",type:"identify",q:"The policy was implemented, for the evidence strongly supported it.",a:"for (reason)",exp:"'For' is a coordinating conjunction giving the reason for the first clause."},
      {id:"cc115",type:"identify",q:"Emissions have decreased, but global temperatures continue to rise.",a:"but (contrast)",exp:"'But' is a coordinating conjunction showing contrast."},
      {id:"cc116",type:"identify",q:"The government increased taxes, so public services improved.",a:"so (result)",exp:"'So' is a coordinating conjunction indicating a result."},
      {id:"cc117",type:"identify",q:"The programme did not reduce crime, nor did it lower drug use.",a:"nor (additional negative)",exp:"'Nor' is a coordinating conjunction adding a second negative statement."},
      {id:"cc118",type:"identify",q:"Healthcare is expensive, but it is a fundamental right.",a:"but (contrast)",exp:"'But' is a coordinating conjunction showing contrast between cost and importance."},
      {id:"cc119",type:"identify",q:"Technology creates convenience, and it drives innovation.",a:"and (addition)",exp:"'And' is a coordinating conjunction adding a related benefit."},
      {id:"cc120",type:"identify",q:"Students must meet the requirements, or they will not graduate.",a:"or (alternative/warning)",exp:"'Or' is a coordinating conjunction warning of the consequence."}
    ]
  },

  subordinatingConjunctions: {
    title: "Subordinating Conjunctions",
    theory: "Subordinating conjunctions (because, although, while, if, when, since, unless, before, after, until, as, whereas, even though, so that, in order that, provided that) introduce dependent clauses and show relationships like cause, contrast, time, and condition.",
    exercises: [
      {id:"sc001",type:"fill",q:"___ the government increased funding, educational outcomes improved significantly.",a:"Because",exp:"'Because' introduces a cause/reason clause. When the dependent clause comes first, use a comma after it."},
      {id:"sc002",type:"fill",q:"___ technology has many benefits, it also poses privacy risks.",a:"Although",exp:"'Although' introduces a contrast/concession clause showing that benefits exist despite risks."},
      {id:"sc003",type:"fill",q:"Students perform better ___ they receive regular feedback from teachers.",a:"when",exp:"'When' introduces a time/condition clause indicating the circumstance under which students perform better."},
      {id:"sc004",type:"fill",q:"The project will not succeed ___ all stakeholders collaborate effectively.",a:"unless",exp:"'Unless' means 'if not' and introduces a necessary condition."},
      {id:"sc005",type:"fill",q:"___ the population continues to age, healthcare costs will inevitably rise.",a:"As",exp:"'As' can mean 'because' or 'while'. Here it introduces a reason/simultaneous condition."},
      {id:"sc006",type:"fill",q:"Researchers continued the experiment ___ they obtained conclusive results.",a:"until",exp:"'Until' shows the time limit: the experiment continued up to the point of obtaining results."},
      {id:"sc007",type:"fill",q:"___ renewable energy costs have decreased, fossil fuel usage remains dominant.",a:"Even though",exp:"'Even though' introduces a strong concession, emphasising surprise that fossil fuels still dominate."},
      {id:"sc008",type:"fill",q:"The government implemented safety regulations ___ workplace accidents could be prevented.",a:"so that",exp:"'So that' introduces a purpose clause explaining why the regulations were implemented."},
      {id:"sc009",type:"fill",q:"___ the study was published, it attracted widespread academic attention.",a:"After",exp:"'After' introduces a time clause showing the sequence of events."},
      {id:"sc010",type:"fill",q:"___ urban areas offer more job opportunities, rural regions provide a better quality of life.",a:"Whereas",exp:"'Whereas' introduces a contrast clause, comparing urban and rural areas."},
      {id:"sc011",type:"fill",q:"The policy will be effective ___ it is enforced consistently.",a:"if",exp:"'If' introduces a conditional clause stating the requirement for effectiveness."},
      {id:"sc012",type:"fill",q:"___ industrialisation began, environmental degradation has accelerated.",a:"Since",exp:"'Since' introduces a time clause indicating the starting point of environmental degradation."},
      {id:"sc013",type:"fill",q:"Citizens should be informed ___ they can make better decisions.",a:"so that",exp:"'So that' introduces a purpose clause explaining why citizens need information."},
      {id:"sc014",type:"fill",q:"___ the data was collected, the researchers began their analysis.",a:"After",exp:"'After' introduces a time clause showing the sequence: collection first, then analysis."},
      {id:"sc015",type:"fill",q:"The hospital remained open ___ demand for services exceeded capacity.",a:"even though",exp:"'Even though' introduces a concession: the hospital stayed open despite being overwhelmed."},
      {id:"sc016",type:"fill",q:"___ students develop critical thinking skills, they are better prepared for the workforce.",a:"When",exp:"'When' introduces a time/condition clause about skill development leading to preparedness."},
      {id:"sc017",type:"fill",q:"Biodiversity will continue to decline ___ conservation efforts are significantly increased.",a:"unless",exp:"'Unless' (meaning 'if not') states the condition needed to prevent continued decline."},
      {id:"sc018",type:"fill",q:"___ the economy recovered, many small businesses had already closed permanently.",a:"Before",exp:"'Before' introduces a time clause showing that closures happened prior to recovery."},
      {id:"sc019",type:"fill",q:"The teacher modified the lesson ___ all students could participate equally.",a:"so that",exp:"'So that' introduces a purpose clause explaining the reason for the modification."},
      {id:"sc020",type:"fill",q:"___ some argue that technology isolates people, others believe it strengthens connections.",a:"While",exp:"'While' introduces a contrast clause presenting an opposing viewpoint."},
      {id:"sc021",type:"fill",q:"___ the treatment was administered, the patient showed gradual improvement.",a:"After",exp:"'After' introduces a time clause showing improvement following treatment."},
      {id:"sc022",type:"fill",q:"The regulation will take effect ___ the parliament approves it.",a:"once",exp:"'Once' introduces a time/condition clause: the regulation depends on parliamentary approval."},
      {id:"sc023",type:"fill",q:"___ the evidence was overwhelming, the committee rejected the proposal.",a:"Although",exp:"'Although' introduces a concession clause: the rejection was unexpected given the evidence."},
      {id:"sc024",type:"fill",q:"Public transport must be improved ___ more people will choose to drive.",a:"before",exp:"'Before' here means 'otherwise' or implies a time limit — improve it before driving increases further."},
      {id:"sc025",type:"fill",q:"The city invested in green spaces ___ residents would have access to nature.",a:"so that",exp:"'So that' introduces a purpose clause explaining the goal of the investment."},
      {id:"sc026",type:"fill",q:"___ automation continues to advance, many traditional jobs will become obsolete.",a:"As",exp:"'As' introduces a time/reason clause about the ongoing process of automation."},
      {id:"sc027",type:"fill",q:"The programme was expanded ___ its initial phase showed promising results.",a:"because",exp:"'Because' introduces a cause clause explaining why the programme was expanded."},
      {id:"sc028",type:"fill",q:"___ the candidate had extensive experience, she was not selected for the position.",a:"Even though",exp:"'Even though' introduces a strong concession emphasising the surprise of non-selection."},
      {id:"sc029",type:"fill",q:"Students should review grammar rules ___ they attempt the writing section.",a:"before",exp:"'Before' introduces a time clause advising review prior to the writing task."},
      {id:"sc030",type:"fill",q:"___ the new law is enacted, the current regulations will remain in force.",a:"Until",exp:"'Until' shows the duration: current regulations apply up to the point of the new law."},
      {id:"sc031",type:"fill",q:"The company relocated its headquarters ___ operating costs in the city had become prohibitive.",a:"because",exp:"'Because' introduces the reason for relocating: prohibitive costs."},
      {id:"sc032",type:"fill",q:"___ the study has limitations, its findings contribute to the existing body of knowledge.",a:"Although",exp:"'Although' introduces a concession acknowledging limitations before stating the contribution."},
      {id:"sc033",type:"fill",q:"Wages have stagnated ___ the cost of living has risen dramatically.",a:"whereas",exp:"'Whereas' introduces a contrast between stagnant wages and rising costs."},
      {id:"sc034",type:"fill",q:"The researchers published their methodology ___ other scientists could replicate the study.",a:"so that",exp:"'So that' introduces a purpose clause: publication enables replication."},
      {id:"sc035",type:"fill",q:"___ governments invest in early childhood education, society benefits in the long term.",a:"When",exp:"'When' introduces a condition/time clause about the benefits of early education investment."},
      {id:"sc036",type:"mc",q:"Which subordinating conjunction shows cause/reason?",options:["because","although","while","unless"],a:0,exp:"'Because' introduces a cause or reason for the main clause."},
      {id:"sc037",type:"mc",q:"Which conjunction introduces a condition?",options:["if","because","although","after"],a:0,exp:"'If' introduces a conditional clause stating a requirement or possibility."},
      {id:"sc038",type:"mc",q:"Where should the comma go: 'Although the study was small it produced significant results'?",options:["After 'small'","After 'Although'","After 'study'","No comma needed"],a:0,exp:"When a dependent clause comes first, place a comma between the dependent and independent clauses."},
      {id:"sc039",type:"mc",q:"Which sentence correctly uses 'unless'?",options:["Unless the budget is increased, the project will be cancelled.","Unless the budget is increased the project will be cancelled.","The project will be cancelled, unless the budget is increased.","Unless, the budget is increased, the project will be cancelled."],a:0,exp:"When the dependent clause (with 'unless') comes first, a comma follows it. Option C also works but typically no comma is used when the independent clause comes first with 'unless'."},
      {id:"sc040",type:"mc",q:"What relationship does 'whereas' show?",options:["Contrast","Cause","Time","Condition"],a:0,exp:"'Whereas' shows contrast, comparing two different situations or ideas."},
      {id:"sc041",type:"mc",q:"Which is a subordinating conjunction?",options:["although","and","but","or"],a:0,exp:"'Although' is a subordinating conjunction. The others are coordinating conjunctions (FANBOYS)."},
      {id:"sc042",type:"mc",q:"Choose the correct sentence:",options:["Because pollution levels are rising, the government has introduced new regulations.","Because pollution levels are rising the government has introduced new regulations.","Because, pollution levels are rising, the government has introduced new regulations.","Pollution levels are rising, because the government has introduced new regulations."],a:0,exp:"When the dependent clause (with 'because') comes first, a comma follows it."},
      {id:"sc043",type:"mc",q:"What does 'so that' express?",options:["Purpose","Contrast","Time","Condition"],a:0,exp:"'So that' introduces a purpose clause explaining why something is done."},
      {id:"sc044",type:"mc",q:"Which conjunction means 'during the same time'?",options:["while","because","unless","after"],a:0,exp:"'While' can mean 'during the same time' (simultaneous events) or show contrast."},
      {id:"sc045",type:"mc",q:"'___ the data is accurate, the conclusions may be unreliable.' Which conjunction fits?",options:["Even though","Because","So that","Until"],a:0,exp:"'Even though' introduces a strong concession: reliable data but potentially unreliable conclusions."},
      {id:"sc046",type:"mc",q:"Which sentence has correct punctuation?",options:["If students study consistently, they will achieve higher grades.","If students study consistently they will achieve higher grades.","Students will achieve higher grades, if they study consistently.","If, students study consistently, they will achieve higher grades."],a:0,exp:"Comma after the dependent clause when it comes first. No comma when the independent clause comes first (option C is incorrect)."},
      {id:"sc047",type:"mc",q:"What type of relationship does 'before' show?",options:["Time","Cause","Contrast","Purpose"],a:0,exp:"'Before' is a subordinating conjunction of time, indicating sequence."},
      {id:"sc048",type:"mc",q:"Which is correct?",options:["The experiment failed because the sample size was too small.","The experiment failed, because the sample size was too small.","The experiment failed. Because the sample size was too small.","Because, the sample size was too small, the experiment failed."],a:0,exp:"When the independent clause comes first and 'because' follows, no comma is typically needed."},
      {id:"sc049",type:"mc",q:"'Provided that all conditions are met, the contract will be valid.' What does 'provided that' express?",options:["Condition","Contrast","Time","Purpose"],a:0,exp:"'Provided that' introduces a condition that must be fulfilled for the main clause to be true."},
      {id:"sc050",type:"mc",q:"What is the error in: 'Although the weather was poor. The event proceeded as planned.'?",options:["The dependent clause is written as a separate sentence (fragment).","'Although' should be 'But'.","There should be no period, only a comma.","Both A and C"],a:3,exp:"A dependent clause cannot stand alone as a sentence. Remove the period and use a comma: 'Although the weather was poor, the event proceeded as planned.'"},
      {id:"sc051",type:"mc",q:"Which conjunction introduces a time clause about a starting point?",options:["since","although","unless","whereas"],a:0,exp:"'Since' can mean 'from the time that', indicating a starting point."},
      {id:"sc052",type:"mc",q:"'The government will implement the policy ___ there is sufficient public support.' Which conjunction fits best?",options:["provided that","because","although","while"],a:0,exp:"'Provided that' sets the condition of public support for policy implementation."},
      {id:"sc053",type:"mc",q:"What is wrong with: 'Because she studied hard, so she passed.'?",options:["Cannot use both 'because' and 'so' — choose one.","'So' should be 'and'.","No comma is needed.","The sentence is correct."],a:0,exp:"Using both 'because' (subordinating) and 'so' (coordinating) is redundant. Use one: 'Because she studied hard, she passed' or 'She studied hard, so she passed.'"},
      {id:"sc054",type:"mc",q:"Which pair of sentences correctly uses 'whereas'?",options:["Urban areas are densely populated, whereas rural areas are sparsely populated.","Whereas urban areas are densely populated. Rural areas are sparsely populated.","Urban areas are densely populated whereas, rural areas are sparsely populated.","Urban, whereas rural areas, are sparsely populated."],a:0,exp:"'Whereas' introduces a contrast clause. A comma precedes it when the independent clause comes first."},
      {id:"sc055",type:"mc",q:"'In order that' is most similar in meaning to:",options:["so that","even though","unless","before"],a:0,exp:"Both 'in order that' and 'so that' introduce purpose clauses."},
      {id:"sc056",type:"mc",q:"Which sentence is a fragment?",options:["Although many students prefer online learning.","Although many students prefer online learning, universities still offer in-person classes.","Many students prefer online learning although universities offer in-person classes.","Universities offer in-person classes although many students prefer online learning."],a:0,exp:"A dependent clause standing alone (starting with 'although' and ending with a period) is a fragment."},
      {id:"sc057",type:"mc",q:"'The city expanded its public transport network ___ traffic congestion could be reduced.' Which conjunction expresses purpose?",options:["so that","because","although","when"],a:0,exp:"'So that' introduces the purpose: reducing traffic congestion."},
      {id:"sc058",type:"mc",q:"What does 'as long as' express?",options:["Condition","Time only","Contrast","Cause"],a:0,exp:"'As long as' expresses a condition, similar to 'provided that' or 'if'."},
      {id:"sc059",type:"mc",q:"Which conjunction is best for: 'The policy was effective ___ it was costly to implement'?",options:["although","because","so that","until"],a:0,exp:"'Although' introduces the concession that the policy was costly, contrasting with its effectiveness."},
      {id:"sc060",type:"mc",q:"'Once the new system is in place, efficiency will improve.' What does 'once' express?",options:["Time/condition","Contrast","Purpose","Reason"],a:0,exp:"'Once' means 'as soon as' or 'when', expressing a time-condition relationship."},
      {id:"sc061",type:"mc",q:"Which is NOT a subordinating conjunction?",options:["yet","because","although","unless"],a:0,exp:"'Yet' is a coordinating conjunction (part of FANBOYS), not a subordinating conjunction."},
      {id:"sc062",type:"mc",q:"'___ the study was conducted with a small sample, the results should be interpreted with caution.' Choose the best conjunction.",options:["Since","So that","Unless","While"],a:0,exp:"'Since' here means 'because', giving the reason for cautious interpretation."},
      {id:"sc063",type:"mc",q:"What is the difference between 'although' and 'even though'?",options:["'Even though' is stronger/more emphatic than 'although'.","'Although' is stronger than 'even though'.","They express different relationships.","'Even though' is informal."],a:0,exp:"Both express concession, but 'even though' is more emphatic, stressing the unexpected nature of the contrast."},
      {id:"sc064",type:"mc",q:"Which subordinating conjunction works for both time and reason?",options:["since","unless","whereas","before"],a:0,exp:"'Since' can mean 'because' (reason) or 'from the time that' (time)."},
      {id:"sc065",type:"mc",q:"'The students will not pass ___ they study more effectively.' Which conjunction fits?",options:["unless","because","although","after"],a:0,exp:"'Unless' means 'if not', stating the condition required for passing."},
      {id:"sc066",type:"error",q:"Although the economy improved, but many people remained unemployed.",a:"Although the economy improved, many people remained unemployed.",exp:"Do not use 'although' with 'but'. 'Although' already signals contrast, so 'but' is redundant."},
      {id:"sc067",type:"error",q:"Because the population is ageing. Healthcare costs continue to rise.",a:"Because the population is ageing, healthcare costs continue to rise.",exp:"A dependent clause beginning with 'because' cannot stand alone. Join it to the independent clause with a comma."},
      {id:"sc068",type:"error",q:"The students passed the exam, because they studied hard.",a:"The students passed the exam because they studied hard.",exp:"When 'because' follows the main clause, no comma is typically needed."},
      {id:"sc069",type:"error",q:"Unless the government act quickly, the crisis will worsen.",a:"Unless the government acts quickly, the crisis will worsen.",exp:"'The government' is a singular subject, so the verb should be 'acts' (third-person singular)."},
      {id:"sc070",type:"error",q:"Even though the evidence was clear but the jury could not reach a verdict.",a:"Even though the evidence was clear, the jury could not reach a verdict.",exp:"Do not use 'but' with 'even though'. Remove 'but' and use a comma after the dependent clause."},
      {id:"sc071",type:"error",q:"While many countries have adopted renewable energy, but others still rely on fossil fuels.",a:"While many countries have adopted renewable energy, others still rely on fossil fuels.",exp:"'While' already introduces contrast, so 'but' is redundant and must be removed."},
      {id:"sc072",type:"error",q:"The company expanded its operations, so that it could reach new markets.",a:"The company expanded its operations so that it could reach new markets.",exp:"No comma before 'so that' when it introduces a purpose clause following the main clause."},
      {id:"sc073",type:"error",q:"After the data was collected. The researchers began their analysis.",a:"After the data was collected, the researchers began their analysis.",exp:"The dependent clause 'After the data was collected' is a fragment. Join it to the main clause with a comma."},
      {id:"sc074",type:"error",q:"Because of the new policy was implemented, waiting times decreased.",a:"Because the new policy was implemented, waiting times decreased.",exp:"'Because of' requires a noun phrase, not a clause. Use 'because' (without 'of') before a full clause."},
      {id:"sc075",type:"error",q:"Since the government have increased funding, more schools have been built.",a:"Since the government has increased funding, more schools have been built.",exp:"'The government' is singular and requires 'has', not 'have'."},
      {id:"sc076",type:"error",q:"Although technology is useful, however, it can be distracting.",a:"Although technology is useful, it can be distracting.",exp:"'Although' and 'however' are both concessive markers. Using both is redundant. Remove 'however'."},
      {id:"sc077",type:"error",q:"If the temperature will rise above 2 degrees, the effects will be catastrophic.",a:"If the temperature rises above 2 degrees, the effects will be catastrophic.",exp:"In conditional clauses with 'if', use present simple (rises), not future tense (will rise)."},
      {id:"sc078",type:"error",q:"Unless the policy is not revised, public dissatisfaction will grow.",a:"Unless the policy is revised, public dissatisfaction will grow.",exp:"'Unless' already means 'if not', so adding 'not' creates a double negative. Remove 'not'."},
      {id:"sc079",type:"error",q:"Whereas some countries invest in education. Others prioritise military spending.",a:"Whereas some countries invest in education, others prioritise military spending.",exp:"The 'whereas' clause is dependent and cannot stand alone. Join with a comma."},
      {id:"sc080",type:"error",q:"Before the students will take the exam, they should review all materials.",a:"Before the students take the exam, they should review all materials.",exp:"In time clauses with 'before', use present simple, not future tense."},
      {id:"sc081",type:"error",q:"The treatment was discontinued because of it caused severe side effects.",a:"The treatment was discontinued because it caused severe side effects.",exp:"'Because' introduces a full clause. 'Because of' takes a noun phrase. Here a clause follows, so use 'because'."},
      {id:"sc082",type:"error",q:"When the new regulations will be enforced, pollution levels should decrease.",a:"When the new regulations are enforced, pollution levels should decrease.",exp:"In time clauses with 'when', use present simple for future reference, not 'will'."},
      {id:"sc083",type:"error",q:"Although the weather was terrible, but the outdoor event was still held.",a:"Although the weather was terrible, the outdoor event was still held.",exp:"'Although' and 'but' cannot be used together. Remove 'but'."},
      {id:"sc084",type:"error",q:"The study found that, since 2010 air quality in major cities has improved.",a:"The study found that since 2010, air quality in major cities has improved.",exp:"The comma should be after '2010' (the time reference), not after 'that'."},
      {id:"sc085",type:"error",q:"So that the students could learn more effectively, the teacher was used new technology.",a:"So that the students could learn more effectively, the teacher used new technology.",exp:"'Was used' is incorrect; the teacher performed the action. Use active voice: 'used'."},
      {id:"sc086",type:"error",q:"Even though she studied very hardly, she did not pass the exam.",a:"Even though she studied very hard, she did not pass the exam.",exp:"'Hard' is both an adjective and adverb. 'Hardly' means 'barely/scarcely', which changes the meaning."},
      {id:"sc087",type:"error",q:"Because the increasing cost of living, many families are struggling financially.",a:"Because of the increasing cost of living, many families are struggling financially.",exp:"'Because' requires a full clause. Before a noun phrase, use 'because of'."},
      {id:"sc088",type:"error",q:"The government introduced subsidies in order that to encourage renewable energy adoption.",a:"The government introduced subsidies in order to encourage renewable energy adoption.",exp:"Use 'in order to + infinitive' or 'in order that + clause'. Mixing both is incorrect."},
      {id:"sc089",type:"error",q:"Until the new hospital will be completed, patients must travel to neighbouring districts.",a:"Until the new hospital is completed, patients must travel to neighbouring districts.",exp:"In time clauses with 'until', use present simple for future events, not 'will'."},
      {id:"sc090",type:"error",q:"As long as the team will work together, they can complete the project on time.",a:"As long as the team works together, they can complete the project on time.",exp:"In conditional clauses with 'as long as', use present simple, not future tense."},
      {id:"sc091",type:"combine",q:"Pollution levels have risen sharply. + The government has not taken any action.",a:"Although pollution levels have risen sharply, the government has not taken any action.",exp:"'Although' shows concession: the lack of action is surprising given rising pollution."},
      {id:"sc092",type:"combine",q:"Students must develop digital literacy skills. + They want to succeed in the modern workplace.",a:"Students must develop digital literacy skills if they want to succeed in the modern workplace.",exp:"'If' introduces the condition under which digital literacy is necessary."},
      {id:"sc093",type:"combine",q:"The population continues to grow. + Water resources are becoming scarcer.",a:"As the population continues to grow, water resources are becoming scarcer.",exp:"'As' shows simultaneous events: population growth occurring alongside water scarcity."},
      {id:"sc094",type:"combine",q:"The experiment was completed. + The researchers submitted their findings for peer review.",a:"After the experiment was completed, the researchers submitted their findings for peer review.",exp:"'After' shows time sequence: completion first, then submission."},
      {id:"sc095",type:"combine",q:"The new law is controversial. + It aims to reduce carbon emissions by 50 percent.",a:"Although the new law is controversial, it aims to reduce carbon emissions by 50 percent.",exp:"'Although' introduces the concession (controversy) before stating the law's purpose."},
      {id:"sc096",type:"combine",q:"Electric vehicles become more affordable. + More consumers will switch from petrol cars.",a:"When electric vehicles become more affordable, more consumers will switch from petrol cars.",exp:"'When' introduces a time/condition clause about future affordability."},
      {id:"sc097",type:"combine",q:"The government invested in early education. + Long-term economic productivity could be improved.",a:"The government invested in early education so that long-term economic productivity could be improved.",exp:"'So that' introduces the purpose of the investment."},
      {id:"sc098",type:"combine",q:"Healthcare costs continue to rise. + Wages have remained stagnant for a decade.",a:"Healthcare costs continue to rise, whereas wages have remained stagnant for a decade.",exp:"'Whereas' contrasts rising costs with stagnant wages."},
      {id:"sc099",type:"combine",q:"The city builds more affordable housing. + The homelessness crisis will persist.",a:"Unless the city builds more affordable housing, the homelessness crisis will persist.",exp:"'Unless' states the necessary condition to prevent the crisis from persisting."},
      {id:"sc100",type:"combine",q:"The research team verified all data. + They published the results.",a:"Before the research team published the results, they verified all data.",exp:"'Before' shows time sequence: verification happened prior to publication."},
      {id:"sc101",type:"combine",q:"Online education has expanded rapidly. + Many students still prefer face-to-face instruction.",a:"Even though online education has expanded rapidly, many students still prefer face-to-face instruction.",exp:"'Even though' introduces a strong concession: preference for in-person learning despite online expansion."},
      {id:"sc102",type:"combine",q:"The factory was closed. + It had been discharging pollutants into the river.",a:"The factory was closed because it had been discharging pollutants into the river.",exp:"'Because' gives the reason for the closure."},
      {id:"sc103",type:"combine",q:"Developing countries face economic challenges. + Developed nations enjoy relative prosperity.",a:"While developing countries face economic challenges, developed nations enjoy relative prosperity.",exp:"'While' introduces a contrast between developing and developed countries."},
      {id:"sc104",type:"combine",q:"The researchers collected sufficient data. + They could draw meaningful conclusions.",a:"The researchers collected sufficient data so that they could draw meaningful conclusions.",exp:"'So that' explains the purpose of collecting sufficient data."},
      {id:"sc105",type:"combine",q:"The government implemented the new curriculum. + Student performance began to improve.",a:"After the government implemented the new curriculum, student performance began to improve.",exp:"'After' shows time sequence: implementation first, then improvement."},
      {id:"sc106",type:"combine",q:"Vaccination programmes are widely available. + Some communities remain hesitant.",a:"Although vaccination programmes are widely available, some communities remain hesitant.",exp:"'Although' introduces a concession: availability exists but hesitancy persists."},
      {id:"sc107",type:"combine",q:"The new technology is adopted widely. + Productivity gains will be significant.",a:"If the new technology is adopted widely, productivity gains will be significant.",exp:"'If' introduces the condition for significant productivity gains."},
      {id:"sc108",type:"combine",q:"The study has several limitations. + Its findings contribute to the field.",a:"Although the study has several limitations, its findings contribute to the field.",exp:"'Although' concedes the limitations before asserting the contribution."},
      {id:"sc109",type:"combine",q:"Air quality deteriorated significantly. + The government introduced emission standards.",a:"After air quality deteriorated significantly, the government introduced emission standards.",exp:"'After' shows that deterioration prompted the introduction of standards."},
      {id:"sc110",type:"combine",q:"Renewable energy sources become more efficient. + Fossil fuels will gradually be phased out.",a:"As renewable energy sources become more efficient, fossil fuels will gradually be phased out.",exp:"'As' shows the gradual process: increasing efficiency leads to fossil fuel phase-out."},
      {id:"sc111",type:"combine",q:"Literacy rates in the region are high. + Economic development remains slow.",a:"Even though literacy rates in the region are high, economic development remains slow.",exp:"'Even though' emphasises the unexpected contrast between literacy and economic development."},
      {id:"sc112",type:"combine",q:"The population ages rapidly. + The pension system will face increasing pressure.",a:"Since the population is ageing rapidly, the pension system will face increasing pressure.",exp:"'Since' introduces the reason (ageing population) for the expected pressure on pensions."},
      {id:"sc113",type:"combine",q:"Public transport infrastructure is expanded. + Traffic congestion will only worsen.",a:"Unless public transport infrastructure is expanded, traffic congestion will only worsen.",exp:"'Unless' states the necessary condition to prevent worsening congestion."},
      {id:"sc114",type:"combine",q:"The semester ends. + All assignments must be submitted.",a:"Before the semester ends, all assignments must be submitted.",exp:"'Before' introduces the time deadline for submission."},
      {id:"sc115",type:"combine",q:"Urbanisation offers economic benefits. + It creates environmental challenges.",a:"Whereas urbanisation offers economic benefits, it creates environmental challenges.",exp:"'Whereas' contrasts the benefits with the challenges of urbanisation."},
      {id:"sc116",type:"identify",q:"Because climate change threatens coastal communities, governments must invest in flood defences.",a:"because (cause/reason)",exp:"'Because' is a subordinating conjunction introducing a cause clause."},
      {id:"sc117",type:"identify",q:"Although the treatment was expensive, many patients opted for it.",a:"although (concession/contrast)",exp:"'Although' is a subordinating conjunction introducing a concession clause."},
      {id:"sc118",type:"identify",q:"If renewable energy costs continue to fall, adoption rates will increase dramatically.",a:"if (condition)",exp:"'If' is a subordinating conjunction introducing a conditional clause."},
      {id:"sc119",type:"identify",q:"The university expanded its online programmes so that international students could enrol.",a:"so that (purpose)",exp:"'So that' is a subordinating conjunction introducing a purpose clause."},
      {id:"sc120",type:"identify",q:"When the new regulations take effect, industries will need to adapt quickly.",a:"when (time)",exp:"'When' is a subordinating conjunction introducing a time clause."},
      {id:"sc121",type:"identify",q:"Unless the funding is secured, the research project will be postponed.",a:"unless (condition — negative)",exp:"'Unless' means 'if not' and introduces a negative conditional clause."},
      {id:"sc122",type:"identify",q:"Whereas developed countries have ageing populations, many developing nations have very young demographics.",a:"whereas (contrast)",exp:"'Whereas' is a subordinating conjunction showing contrast between two situations."},
      {id:"sc123",type:"identify",q:"The company restructured its operations before the new financial regulations came into effect.",a:"before (time)",exp:"'Before' is a subordinating conjunction introducing a time clause about sequence."},
      {id:"sc124",type:"identify",q:"Even though the data supported the hypothesis, the researchers remained cautious.",a:"even though (strong concession)",exp:"'Even though' is a subordinating conjunction introducing a strong concession/contrast."},
      {id:"sc125",type:"identify",q:"Since the introduction of the carbon tax, emissions have decreased by 15 percent.",a:"since (time — starting point)",exp:"'Since' here is a subordinating conjunction of time, indicating a starting point."},
      {id:"sc126",type:"identify",q:"As urbanisation accelerates, the demand for public services increases proportionally.",a:"as (time/reason — simultaneous)",exp:"'As' is a subordinating conjunction showing simultaneous events or a causal link."},
      {id:"sc127",type:"identify",q:"The study was conducted so that policymakers could make evidence-based decisions.",a:"so that (purpose)",exp:"'So that' introduces a purpose clause explaining why the study was conducted."},
      {id:"sc128",type:"identify",q:"After the policy was revised, public satisfaction increased significantly.",a:"after (time — sequence)",exp:"'After' is a subordinating conjunction showing time sequence."},
      {id:"sc129",type:"identify",q:"While some experts advocate for stricter regulations, others prefer market-based solutions.",a:"while (contrast)",exp:"'While' here is a subordinating conjunction showing contrast between two viewpoints."},
      {id:"sc130",type:"identify",q:"The programme will continue provided that funding remains available.",a:"provided that (condition)",exp:"'Provided that' is a subordinating conjunction introducing a conditional clause."}
    ]
  },

  correlativeConjunctions: {
    title: "Correlative Conjunctions",
    theory: "Correlative conjunctions work in pairs: both...and, either...or, neither...nor, not only...but also, whether...or, as...as, such...that, no sooner...than, hardly...when, scarcely...when. They connect balanced elements.",
    exercises: [
      {id:"cr001",type:"fill",q:"Both the government ___ the private sector must invest in renewable energy.",a:"and",exp:"'Both...and' is a correlative pair. 'And' completes the pair to connect two subjects."},
      {id:"cr002",type:"fill",q:"Either the school improves its facilities, ___ enrolment numbers will continue to decline.",a:"or",exp:"'Either...or' presents two alternatives. 'Or' completes the pair."},
      {id:"cr003",type:"fill",q:"Neither the researchers ___ the funding body anticipated such significant results.",a:"nor",exp:"'Neither...nor' connects two negative elements. 'Nor' completes the pair."},
      {id:"cr004",type:"fill",q:"Not only does technology enhance learning, ___ it also prepares students for the workforce.",a:"but",exp:"'Not only...but also' emphasises two positive aspects. 'But' (followed by 'also') completes the pair."},
      {id:"cr005",type:"fill",q:"Whether students choose online learning ___ face-to-face instruction, they must meet the same standards.",a:"or",exp:"'Whether...or' presents two alternatives. 'Or' completes the pair."},
      {id:"cr006",type:"fill",q:"The new policy is ___ effective as the previous one in reducing emissions.",a:"as",exp:"'As...as' compares two elements of equal degree. The first 'as' precedes the adjective."},
      {id:"cr007",type:"fill",q:"No sooner had the government announced the policy ___ public debate erupted.",a:"than",exp:"'No sooner...than' indicates one event immediately following another. 'Than' completes the pair."},
      {id:"cr008",type:"fill",q:"Hardly had the study been published ___ its methodology was questioned.",a:"when",exp:"'Hardly...when' indicates one event immediately following another. 'When' completes the pair."},
      {id:"cr009",type:"fill",q:"The evidence was ___ compelling that the committee approved the proposal unanimously.",a:"such",exp:"'Such...that' emphasises the degree of a quality leading to a result. 'Such' precedes a noun phrase."},
      {id:"cr010",type:"fill",q:"Both economic growth ___ environmental sustainability should be priorities for governments.",a:"and",exp:"'Both...and' connects two parallel noun phrases as joint priorities."},
      {id:"cr011",type:"fill",q:"Not only has urbanisation increased traffic congestion, ___ it has also worsened air quality.",a:"but",exp:"'Not only...but also' connects two negative effects of urbanisation."},
      {id:"cr012",type:"fill",q:"Neither the mayor ___ the council members supported the proposed budget cuts.",a:"nor",exp:"'Neither...nor' connects two subjects who both failed to support the cuts."},
      {id:"cr013",type:"fill",q:"Either the hospital hires additional staff, ___ patient care will deteriorate.",a:"or",exp:"'Either...or' presents the consequence if staff are not hired."},
      {id:"cr014",type:"fill",q:"The pollution was ___ severe that schools were forced to close for a week.",a:"so",exp:"'So...that' emphasises the degree of severity leading to a result. 'So' precedes an adjective."},
      {id:"cr015",type:"fill",q:"Scarcely had the new curriculum been introduced ___ teachers began reporting improvements.",a:"when",exp:"'Scarcely...when' indicates one event immediately following another."},
      {id:"cr016",type:"fill",q:"Both healthcare professionals ___ patients benefit from advances in medical technology.",a:"and",exp:"'Both...and' connects two groups who share in the benefits."},
      {id:"cr017",type:"fill",q:"Not only did the programme reduce unemployment, ___ it also stimulated local business growth.",a:"but",exp:"'Not only...but also' highlights two positive outcomes."},
      {id:"cr018",type:"fill",q:"The challenge was ___ great that many organisations withdrew from the project.",a:"so",exp:"'So...that' expresses a degree leading to a consequence."},
      {id:"cr019",type:"fill",q:"Whether the economy improves ___ worsens, the government must maintain essential services.",a:"or",exp:"'Whether...or' presents two possible scenarios requiring the same response."},
      {id:"cr020",type:"fill",q:"Neither increased funding ___ additional training resolved the performance issues.",a:"nor",exp:"'Neither...nor' shows that two attempted solutions both failed."},
      {id:"cr021",type:"fill",q:"Hardly had the emergency been declared ___ aid organisations began mobilising resources.",a:"when",exp:"'Hardly...when' shows the rapid response following the emergency declaration."},
      {id:"cr022",type:"fill",q:"The demand for housing was ___ great that prices doubled within five years.",a:"such",exp:"'Such' before a noun ('such great demand') can be rephrased as 'so great that' with the adjective alone. Both 'such' and 'so' work here, but 'such' precedes the noun phrase."},
      {id:"cr023",type:"fill",q:"Both developed ___ developing countries face the challenge of climate change.",a:"and",exp:"'Both...and' connects two categories that share the same challenge."},
      {id:"cr024",type:"fill",q:"No sooner had the vaccine been approved ___ distribution began worldwide.",a:"than",exp:"'No sooner...than' shows immediate sequence: approval followed instantly by distribution."},
      {id:"cr025",type:"fill",q:"Online learning is not ___ effective as traditional classroom instruction for all students.",a:"as",exp:"'Not as...as' makes a negative comparison. The first 'as' precedes the adjective."},
      {id:"cr026",type:"mc",q:"Which correlative conjunction pair correctly completes: '___ the study was well-designed, ___ it produced reliable results'?",options:["Not only...but also","Both...and","Either...or","Neither...nor"],a:0,exp:"'Not only was the study well-designed, but it also produced reliable results' emphasises two positive qualities."},
      {id:"cr027",type:"mc",q:"What is the correct word order after 'not only' at the start of a sentence?",options:["Inverted (auxiliary + subject)","Normal (subject + verb)","Passive voice only","Infinitive form"],a:0,exp:"When 'not only' begins a sentence, inversion is required: 'Not only does/did/has + subject + verb'."},
      {id:"cr028",type:"mc",q:"Choose the correct sentence:",options:["Neither the students nor the teacher was aware of the change.","Neither the students nor the teacher were aware of the change.","Neither the students or the teacher was aware of the change.","Neither the students nor the teacher is aware of the change."],a:0,exp:"With 'neither...nor', the verb agrees with the nearest subject ('the teacher' — singular, so 'was')."},
      {id:"cr029",type:"mc",q:"Which pair expresses a comparison of equal degree?",options:["as...as","not only...but also","either...or","no sooner...than"],a:0,exp:"'As...as' compares two things of equal degree: 'as important as'."},
      {id:"cr030",type:"mc",q:"'Both education and healthcare are essential.' What parts of speech does 'both...and' connect here?",options:["Nouns","Verbs","Adjectives","Adverbs"],a:0,exp:"'Both...and' connects the nouns 'education' and 'healthcare'."},
      {id:"cr031",type:"mc",q:"Which sentence correctly uses 'either...or'?",options:["Either the government reduces emissions, or it faces international sanctions.","Either the government reduces emissions, or, it faces international sanctions.","Either, the government reduces emissions, or it faces international sanctions.","Either the government reduces emissions or, it faces international sanctions."],a:0,exp:"'Either...or' connects two clauses with a comma before 'or' when joining independent clauses."},
      {id:"cr032",type:"mc",q:"'No sooner had the policy been announced than public protests began.' What does this express?",options:["Immediate sequence — one event right after another","Cause and effect","Contrast","Condition"],a:0,exp:"'No sooner...than' indicates that protests began immediately after the announcement."},
      {id:"cr033",type:"mc",q:"In 'Not only did emissions decrease, but air quality also improved', why is the first clause inverted?",options:["'Not only' at the start requires subject-auxiliary inversion.","It is a question.","It is passive voice.","'Not only' is a subordinating conjunction."],a:0,exp:"When 'not only' begins a sentence, inversion occurs: auxiliary verb before subject."},
      {id:"cr034",type:"mc",q:"Which correlative pair shows that two negative things are true?",options:["neither...nor","either...or","both...and","not only...but also"],a:0,exp:"'Neither...nor' connects two negative elements, showing that both are not the case."},
      {id:"cr035",type:"mc",q:"'Whether the results are positive or negative, the study must be published.' What does 'whether...or' express?",options:["Two possibilities with the same outcome","A condition","A cause","A sequence"],a:0,exp:"'Whether...or' presents two possible scenarios that lead to the same conclusion."},
      {id:"cr036",type:"mc",q:"Choose the correct parallel structure: 'The new policy not only reduces poverty but also ___.'",options:["improves healthcare access","it improves healthcare access","improving healthcare access","healthcare access is improved"],a:0,exp:"Parallel structure requires matching verb forms: 'reduces' and 'improves' (both present simple)."},
      {id:"cr037",type:"mc",q:"Which sentence has correct subject-verb agreement?",options:["Either the minister or the advisers are responsible.","Either the minister or the advisers is responsible.","Either the minister nor the advisers are responsible.","Either the minister or the advisers was responsible."],a:0,exp:"With 'either...or', the verb agrees with the nearest subject ('advisers' — plural, so 'are')."},
      {id:"cr038",type:"mc",q:"'Such was the impact of the policy that employment rates doubled.' What does 'such...that' express?",options:["Degree/result — the impact was so significant it caused doubling.","Contrast","Condition","Time sequence"],a:0,exp:"'Such...that' expresses the degree of something leading to a specific result."},
      {id:"cr039",type:"mc",q:"Which is the correct negative form of 'both...and'?",options:["neither...nor","either...or","not only...but also","whether...or"],a:0,exp:"'Neither...nor' is the negative counterpart of 'both...and'."},
      {id:"cr040",type:"mc",q:"'Hardly had the lecture begun ___ the fire alarm sounded.' What completes this?",options:["when","than","and","but"],a:0,exp:"'Hardly...when' is the correct correlative pair. 'When' completes it."},
      {id:"cr041",type:"mc",q:"Choose the correct sentence with 'both...and':",options:["The programme benefits both students and teachers.","The programme both benefits students and teachers.","The programme benefits both students and also teachers.","Both the programme benefits students and teachers."],a:0,exp:"'Both' should be placed directly before the first of the two parallel elements it connects."},
      {id:"cr042",type:"mc",q:"Which correlative pair requires inverted word order in the first clause?",options:["not only...but also (when 'not only' starts the sentence)","both...and","either...or","whether...or"],a:0,exp:"'Not only' at the beginning of a sentence triggers subject-auxiliary inversion."},
      {id:"cr043",type:"mc",q:"'The research was neither thorough ___ well-funded.' Which word completes this?",options:["nor","or","and","but"],a:0,exp:"'Neither...nor' is the correct pair. 'Nor' connects the second negative element."},
      {id:"cr044",type:"mc",q:"What does 'scarcely...when' express?",options:["One event happening almost immediately after another","Contrast between two events","A repeated event","Cause and effect"],a:0,exp:"'Scarcely...when' indicates that the second event occurred almost immediately after the first."},
      {id:"cr045",type:"mc",q:"Which sentence correctly uses 'not only...but also'?",options:["Not only is education a right, but it is also an investment in the future.","Not only education is a right, but also it is an investment.","Not only is education a right, but also is an investment in the future.","Not only education is a right, but it is also an investment."],a:0,exp:"When 'not only' starts the sentence, use inversion in the first clause, and 'but + subject + also + verb' in the second."},
      {id:"cr046",type:"error",q:"Both the teacher and the student was present at the meeting.",a:"Both the teacher and the student were present at the meeting.",exp:"'Both...and' creates a compound subject that is always plural, requiring 'were'."},
      {id:"cr047",type:"error",q:"Not only the policy failed, but it also caused public outrage.",a:"Not only did the policy fail, but it also caused public outrage.",exp:"When 'not only' starts the sentence, inversion is required: 'Not only did the policy fail'."},
      {id:"cr048",type:"error",q:"Neither the students or the teachers agreed with the new timetable.",a:"Neither the students nor the teachers agreed with the new timetable.",exp:"'Neither' pairs with 'nor', not 'or'. The correct pair is 'neither...nor'."},
      {id:"cr049",type:"error",q:"Either you submit the report on time, or else you will receive a penalty.",a:"Either you submit the report on time, or you will receive a penalty.",exp:"'Or else' is redundant with 'either...or'. Remove 'else'."},
      {id:"cr050",type:"error",q:"The government not only raised taxes but also was cutting public services.",a:"The government not only raised taxes but also cut public services.",exp:"Parallel structure requires matching verb forms: 'raised' and 'cut' (both past simple)."},
      {id:"cr051",type:"error",q:"Both increased investment and also better training are needed.",a:"Both increased investment and better training are needed.",exp:"'Both...and' does not take 'also'. Remove 'also' to correct the sentence."},
      {id:"cr052",type:"error",q:"No sooner the results were announced when celebrations began.",a:"No sooner had the results been announced than celebrations began.",exp:"'No sooner' requires inversion (had + subject) and pairs with 'than', not 'when'."},
      {id:"cr053",type:"error",q:"Neither the report was thorough nor it was submitted on time.",a:"Neither was the report thorough, nor was it submitted on time.",exp:"When 'neither' starts a clause, inversion is needed in both clauses."},
      {id:"cr054",type:"error",q:"The data was so compelling so that the committee approved the proposal immediately.",a:"The data was so compelling that the committee approved the proposal immediately.",exp:"'So...that' is the correct pair. Remove the extra 'so' before 'that'."},
      {id:"cr055",type:"error",q:"Hardly the study had been published when its findings were challenged.",a:"Hardly had the study been published when its findings were challenged.",exp:"'Hardly' at the start requires inversion: 'Hardly had + subject + past participle'."},
      {id:"cr056",type:"error",q:"Whether you agree or disagree with the policy, but you must comply with it.",a:"Whether you agree or disagree with the policy, you must comply with it.",exp:"'Whether...or' already introduces two alternatives. 'But' is redundant and should be removed."},
      {id:"cr057",type:"error",q:"Not only education improves employment prospects, but it also strengthens communities.",a:"Not only does education improve employment prospects, but it also strengthens communities.",exp:"'Not only' at the start requires inversion: 'Not only does + subject + base verb'."},
      {id:"cr058",type:"error",q:"The programme benefits neither the students and the teachers.",a:"The programme benefits neither the students nor the teachers.",exp:"'Neither' pairs with 'nor', not 'and'."},
      {id:"cr059",type:"error",q:"Scarcely had the budget been approved, than the spending began.",a:"Scarcely had the budget been approved when the spending began.",exp:"'Scarcely' pairs with 'when', not 'than'. Only 'no sooner' pairs with 'than'."},
      {id:"cr060",type:"error",q:"Both the quality and also the quantity of research output has improved.",a:"Both the quality and the quantity of research output have improved.",exp:"Remove 'also' (redundant with 'both...and') and use 'have' (plural subject)."},
      {id:"cr061",type:"transform",q:"Technology has improved healthcare. Technology has also improved education. [Use not only...but also]",a:"Not only has technology improved healthcare, but it has also improved education.",exp:"'Not only...but also' combines two achievements. Inversion is used because 'not only' starts the sentence."},
      {id:"cr062",type:"transform",q:"The government can invest in education. The government can invest in infrastructure. [Use either...or]",a:"The government can invest either in education or in infrastructure.",exp:"'Either...or' presents two choices. Place 'either' before the first parallel element."},
      {id:"cr063",type:"transform",q:"The policy did not reduce crime. The policy did not improve public safety. [Use neither...nor]",a:"The policy neither reduced crime nor improved public safety.",exp:"'Neither...nor' joins two negative outcomes with parallel verb forms."},
      {id:"cr064",type:"transform",q:"Students must study grammar. Students must also practise writing. [Use both...and]",a:"Students must study both grammar and writing.",exp:"'Both...and' connects the two objects in a parallel structure."},
      {id:"cr065",type:"transform",q:"The impact was very significant. The entire community benefited. [Use such...that]",a:"Such was the impact that the entire community benefited.",exp:"'Such...that' emphasises the significance leading to a result. Inversion adds emphasis."},
      {id:"cr066",type:"transform",q:"It does not matter if the economy improves. It does not matter if it declines. The government must support vulnerable groups. [Use whether...or]",a:"Whether the economy improves or declines, the government must support vulnerable groups.",exp:"'Whether...or' presents two scenarios with the same required action."},
      {id:"cr067",type:"transform",q:"The new regulation was announced. Immediately, businesses began to comply. [Use no sooner...than]",a:"No sooner had the new regulation been announced than businesses began to comply.",exp:"'No sooner...than' shows immediate sequence with inversion in the first clause."},
      {id:"cr068",type:"transform",q:"Education is important for individuals. Education is important for society. [Use both...and]",a:"Education is important for both individuals and society.",exp:"'Both...and' connects two parallel prepositional objects."},
      {id:"cr069",type:"transform",q:"The pollution was very severe. Many residents developed respiratory issues. [Use so...that]",a:"The pollution was so severe that many residents developed respiratory issues.",exp:"'So...that' expresses the degree of severity leading to a health consequence."},
      {id:"cr070",type:"transform",q:"Automation reduces costs. Automation also increases efficiency. [Use not only...but also]",a:"Automation not only reduces costs but also increases efficiency.",exp:"'Not only...but also' connects two benefits with parallel verb structures."},
      {id:"cr071",type:"transform",q:"The study began. Almost immediately, criticism emerged. [Use hardly...when]",a:"Hardly had the study begun when criticism emerged.",exp:"'Hardly...when' shows near-immediate sequence with inversion in the first clause."},
      {id:"cr072",type:"transform",q:"Renewable energy is clean. Fossil fuel energy is not as clean. [Use as...as]",a:"Fossil fuel energy is not as clean as renewable energy.",exp:"'Not as...as' makes a negative comparison showing inequality."},
      {id:"cr073",type:"transform",q:"The results were surprising. The committee decided to fund further research. [Use such...that]",a:"The results were such that the committee decided to fund further research.",exp:"'Such...that' emphasises the surprising nature of the results leading to a decision."},
      {id:"cr074",type:"transform",q:"The city can expand public transport. The city can build new roads. [Use either...or]",a:"The city can either expand public transport or build new roads.",exp:"'Either...or' presents two alternative actions with parallel verb forms."},
      {id:"cr075",type:"transform",q:"Climate change affects agriculture. Climate change also affects water supplies. [Use not only...but also]",a:"Climate change affects not only agriculture but also water supplies.",exp:"'Not only...but also' connects two objects affected by climate change."},
      {id:"cr076",type:"identify",q:"Both researchers and policymakers agree that education funding must increase.",a:"both...and (addition — connecting two subjects)",exp:"'Both...and' is a correlative conjunction pair connecting two parallel subjects."},
      {id:"cr077",type:"identify",q:"Not only has technology improved productivity, but it has also transformed communication.",a:"not only...but also (emphatic addition)",exp:"'Not only...but also' is a correlative conjunction pair emphasising two related points."},
      {id:"cr078",type:"identify",q:"Neither the proposed budget nor the timeline was approved by the committee.",a:"neither...nor (double negative — connecting two subjects)",exp:"'Neither...nor' is a correlative conjunction pair connecting two items that were both rejected."},
      {id:"cr079",type:"identify",q:"Whether students attend in person or participate online, they receive the same qualification.",a:"whether...or (two alternatives with same outcome)",exp:"'Whether...or' is a correlative conjunction pair presenting two possibilities."},
      {id:"cr080",type:"identify",q:"No sooner had the reforms been implemented than economic indicators began to improve.",a:"no sooner...than (immediate sequence)",exp:"'No sooner...than' is a correlative conjunction pair indicating one event immediately followed another."}
    ]
  },

  compoundSentences: {
    title: "Compound Sentences",
    theory: "A compound sentence joins two or more independent clauses using coordinating conjunctions (with comma), semicolons, or transitional expressions (semicolon + however/therefore/moreover + comma). Each clause could stand alone as a sentence.",
    exercises: [
      {id:"cs001",type:"fill",q:"Education empowers individuals; ___, it strengthens communities as a whole.",a:"moreover",exp:"'Moreover' is a transitional expression meaning 'in addition'. It follows a semicolon and is followed by a comma."},
      {id:"cs002",type:"fill",q:"The government increased healthcare funding; ___, hospital waiting times decreased.",a:"consequently",exp:"'Consequently' shows result. It follows a semicolon and is followed by a comma in a compound sentence."},
      {id:"cs003",type:"fill",q:"Renewable energy is becoming more affordable; ___, many countries still rely heavily on fossil fuels.",a:"however",exp:"'However' shows contrast. It follows a semicolon and is followed by a comma."},
      {id:"cs004",type:"fill",q:"The evidence strongly supported the hypothesis; ___, the researchers published their findings.",a:"therefore",exp:"'Therefore' shows logical conclusion. It follows a semicolon and is followed by a comma."},
      {id:"cs005",type:"fill",q:"Air pollution has decreased in urban centres; ___, water quality in nearby rivers has improved.",a:"furthermore",exp:"'Furthermore' adds information. It follows a semicolon and is followed by a comma."},
      {id:"cs006",type:"fill",q:"Vaccination rates have increased significantly; ___, some communities remain resistant to immunisation.",a:"nevertheless",exp:"'Nevertheless' shows concession/contrast: despite increased rates, resistance persists."},
      {id:"cs007",type:"fill",q:"The university expanded its online courses; ___, it attracted students from over fifty countries.",a:"as a result",exp:"'As a result' shows consequence. It follows a semicolon and is followed by a comma."},
      {id:"cs008",type:"fill",q:"Public transport is efficient in major cities; ___, rural areas often lack adequate services.",a:"in contrast",exp:"'In contrast' highlights a difference between urban and rural transport."},
      {id:"cs009",type:"fill",q:"The budget deficit continues to grow; ___, essential services must still be maintained.",a:"nonetheless",exp:"'Nonetheless' shows concession: services must continue despite the deficit."},
      {id:"cs010",type:"fill",q:"Technology has transformed the workplace; ___, it has revolutionised the education sector.",a:"likewise",exp:"'Likewise' shows similarity: technology transformed both workplaces and education."},
      {id:"cs011",type:"fill",q:"The policy failed to achieve its objectives ___ it was implemented without adequate consultation.",a:", for",exp:"'For' as a coordinating conjunction gives the reason. A comma precedes it."},
      {id:"cs012",type:"fill",q:"The economy grew steadily ___ unemployment rates fell to a record low.",a:", and",exp:"'And' joins two related positive outcomes. A comma precedes it before an independent clause."},
      {id:"cs013",type:"fill",q:"Healthcare costs continue to rise; ___, governments must find sustainable funding solutions.",a:"therefore",exp:"'Therefore' shows logical consequence following the rising costs."},
      {id:"cs014",type:"fill",q:"The research was groundbreaking; ___, it received widespread media coverage.",a:"accordingly",exp:"'Accordingly' means 'as a result' or 'in response'. It follows a semicolon and is followed by a comma."},
      {id:"cs015",type:"fill",q:"Climate change poses significant risks; ___, many nations have committed to emission reduction targets.",a:"hence",exp:"'Hence' shows consequence. The risks prompted nations to commit to targets."},
      {id:"cs016",type:"fill",q:"The experiment was repeated three times; ___, the same results were obtained.",a:"each time",exp:"'Each time' shows repetition of results across multiple trials. It follows a semicolon."},
      {id:"cs017",type:"fill",q:"Student debt has increased dramatically; ___, fewer young people can afford to buy homes.",a:"as a consequence",exp:"'As a consequence' shows the result of increasing student debt on home ownership."},
      {id:"cs018",type:"fill",q:"The organisation promoted healthy eating; ___, it also encouraged regular physical activity.",a:"in addition",exp:"'In addition' adds a related initiative alongside the healthy eating promotion."},
      {id:"cs019",type:"fill",q:"Immigration has declined in recent years; ___, the labour market is experiencing shortages.",a:"consequently",exp:"'Consequently' links the decline in immigration to labour market shortages."},
      {id:"cs020",type:"fill",q:"The data was carefully verified; ___, the analysis proceeded smoothly.",a:"as a result",exp:"'As a result' shows that careful verification led to a smooth analysis."},
      {id:"cs021",type:"fill",q:"Urban areas offer many employment opportunities; ___, they also have a higher cost of living.",a:"however",exp:"'However' contrasts the employment opportunities with the higher cost of living."},
      {id:"cs022",type:"fill",q:"Automation improves efficiency in manufacturing; ___, it has similar benefits in the service sector.",a:"similarly",exp:"'Similarly' draws a comparison between manufacturing and service sector benefits."},
      {id:"cs023",type:"fill",q:"The school introduced a new anti-bullying programme; ___, incidents decreased by 40 percent.",a:"subsequently",exp:"'Subsequently' shows the positive result that followed the programme introduction."},
      {id:"cs024",type:"fill",q:"The government must reduce spending ___ it will face a fiscal crisis within five years.",a:", or",exp:"'Or' warns of the consequence. A comma precedes it before the independent clause."},
      {id:"cs025",type:"fill",q:"Public libraries provide essential community services; ___, they offer free internet access to disadvantaged groups.",a:"in particular",exp:"'In particular' specifies one notable service that libraries offer."},
      {id:"cs026",type:"fill",q:"Deforestation has accelerated in the tropics; ___, biodiversity loss has reached critical levels.",a:"consequently",exp:"'Consequently' shows the direct result of deforestation on biodiversity."},
      {id:"cs027",type:"fill",q:"The study had several methodological strengths; ___, it also had notable limitations.",a:"nevertheless",exp:"'Nevertheless' introduces a contrast: acknowledging strengths before noting limitations."},
      {id:"cs028",type:"fill",q:"Many countries have banned single-use plastics; ___, Australia has introduced several restrictions.",a:"for example",exp:"'For example' provides a specific instance of the broader trend."},
      {id:"cs029",type:"fill",q:"Funding for the arts has been reduced; ___, many cultural institutions have been forced to close.",a:"as a result",exp:"'As a result' shows the consequence of funding cuts on cultural institutions."},
      {id:"cs030",type:"fill",q:"The new hospital was completed on schedule; ___, it was also built under budget.",a:"furthermore",exp:"'Furthermore' adds a second positive achievement to the on-schedule completion."},
      {id:"cs031",type:"fill",q:"Exercise improves physical health; ___, it benefits mental well-being.",a:"additionally",exp:"'Additionally' adds information about a further benefit of exercise."},
      {id:"cs032",type:"fill",q:"Remote work reduces commuting time; ___, it may lead to feelings of professional isolation.",a:"on the other hand",exp:"'On the other hand' presents an opposing perspective on remote work."},
      {id:"cs033",type:"fill",q:"The government implemented strict lockdowns; ___, infection rates began to decline within weeks.",a:"as a result",exp:"'As a result' links the strict lockdowns to the decline in infection rates."},
      {id:"cs034",type:"fill",q:"Early childhood education yields long-term benefits; ___, investment in this area should be a priority.",a:"therefore",exp:"'Therefore' shows the logical conclusion: benefits justify prioritising investment."},
      {id:"cs035",type:"fill",q:"The evidence was inconclusive; ___, the committee deferred its decision until further data was available.",a:"accordingly",exp:"'Accordingly' shows the committee's response to the inconclusive evidence."},
      {id:"cs036",type:"fill",q:"Social media connects people globally; ___, it can also spread misinformation rapidly.",a:"however",exp:"'However' contrasts the positive connectivity with the negative spread of misinformation."},
      {id:"cs037",type:"fill",q:"The city invested in cycling infrastructure; ___, the number of cyclists doubled within two years.",a:"consequently",exp:"'Consequently' shows the result of the infrastructure investment."},
      {id:"cs038",type:"fill",q:"International students contribute to cultural diversity; ___, they generate significant revenue for universities.",a:"moreover",exp:"'Moreover' adds a second benefit of international students."},
      {id:"cs039",type:"fill",q:"Average temperatures have risen by 1.5 degrees; ___, extreme weather events have become more frequent.",a:"meanwhile",exp:"'Meanwhile' shows two simultaneous trends related to climate change."},
      {id:"cs040",type:"fill",q:"The research protocol was approved; ___, data collection began the following month.",a:"subsequently",exp:"'Subsequently' shows the next event in the sequence after approval."},
      {id:"cs041",type:"mc",q:"Which is a correct compound sentence?",options:["The research was thorough; however, the conclusions were debatable.","The research was thorough, however, the conclusions were debatable.","The research was thorough however the conclusions were debatable.","The research was thorough; however the conclusions were debatable."],a:0,exp:"Transitional expressions require a semicolon before and a comma after: 'thorough; however, the conclusions'."},
      {id:"cs042",type:"mc",q:"What makes a sentence 'compound'?",options:["It has two or more independent clauses.","It has one independent and one dependent clause.","It has a subject and a verb.","It uses transitional words."],a:0,exp:"A compound sentence contains two or more independent clauses, each of which could stand alone."},
      {id:"cs043",type:"mc",q:"Which punctuation correctly joins two independent clauses without a conjunction?",options:["A semicolon","A comma","A colon","No punctuation"],a:0,exp:"A semicolon can join two closely related independent clauses without a conjunction."},
      {id:"cs044",type:"mc",q:"What is wrong with: 'The economy improved, therefore unemployment decreased.'?",options:["Comma splice — 'therefore' is not a coordinating conjunction.","Nothing — the sentence is correct.","'Therefore' should be 'and'.","A period should follow 'improved'."],a:0,exp:"'Therefore' is a transitional expression, not a coordinating conjunction. Use a semicolon: 'improved; therefore, unemployment decreased.'"},
      {id:"cs045",type:"mc",q:"Which transitional expression shows contrast?",options:["however","therefore","moreover","consequently"],a:0,exp:"'However' is a transitional expression that shows contrast between two ideas."},
      {id:"cs046",type:"mc",q:"Choose the correct compound sentence:",options:["Technology creates opportunities, but it also presents challenges.","Technology creates opportunities but, it also presents challenges.","Technology creates opportunities, but, it also presents challenges.","Technology creates opportunities; but it also presents challenges."],a:0,exp:"Comma before the coordinating conjunction 'but' when joining two independent clauses. No comma after 'but'."},
      {id:"cs047",type:"mc",q:"Which is NOT a way to form a compound sentence?",options:["Using a subordinating conjunction","Using a coordinating conjunction with a comma","Using a semicolon","Using a semicolon with a transitional expression"],a:0,exp:"Subordinating conjunctions create complex sentences (with dependent clauses), not compound sentences."},
      {id:"cs048",type:"mc",q:"'Education is a fundamental right; moreover, it is an investment in national prosperity.' What does 'moreover' express?",options:["Addition — adding a further point","Contrast","Result","Time"],a:0,exp:"'Moreover' adds emphasis to a further point, meaning 'in addition' or 'furthermore'."},
      {id:"cs049",type:"mc",q:"Which sentence has a run-on error?",options:["The government raised taxes the public protested loudly.","The government raised taxes, and the public protested loudly.","The government raised taxes; the public protested loudly.","The government raised taxes; consequently, the public protested loudly."],a:0,exp:"Two independent clauses with no punctuation or conjunction create a run-on sentence."},
      {id:"cs050",type:"mc",q:"What punctuation goes before 'nevertheless' when joining two clauses?",options:["A semicolon","A comma","A colon","Nothing"],a:0,exp:"Transitional expressions like 'nevertheless' require a semicolon before them when joining two independent clauses."},
      {id:"cs051",type:"mc",q:"Which transitional expression means 'as a result'?",options:["consequently","however","furthermore","likewise"],a:0,exp:"'Consequently' means 'as a result', showing a cause-and-effect relationship."},
      {id:"cs052",type:"mc",q:"How does a compound sentence differ from a simple sentence with a compound verb?",options:["A compound sentence has two subjects and two verbs in separate clauses; a compound verb shares one subject.","There is no difference.","A compound sentence is always longer.","A compound verb uses more conjunctions."],a:0,exp:"A compound sentence has multiple independent clauses (each with subject + verb), while a compound verb has one subject with two or more verbs."},
      {id:"cs053",type:"mc",q:"'Emissions must be reduced; otherwise, the climate targets will not be met.' What does 'otherwise' mean?",options:["If not — presenting the consequence of inaction","In addition","Similarly","Therefore"],a:0,exp:"'Otherwise' means 'if not' and presents the consequence of not reducing emissions."},
      {id:"cs054",type:"mc",q:"Which is a correct compound sentence using a semicolon?",options:["The study was comprehensive; the results were reliable.","The study was comprehensive, the results were reliable.","The study was comprehensive; and the results were reliable.","The study was comprehensive the results were reliable."],a:0,exp:"A semicolon alone can join two closely related independent clauses without a conjunction."},
      {id:"cs055",type:"mc",q:"'The policy was unpopular, yet it achieved its goals.' What type of sentence is this?",options:["Compound","Complex","Simple","Compound-complex"],a:0,exp:"Two independent clauses joined by a comma + coordinating conjunction ('yet') form a compound sentence."},
      {id:"cs056",type:"mc",q:"Which word is a transitional expression, NOT a coordinating conjunction?",options:["therefore","and","but","or"],a:0,exp:"'Therefore' is a transitional expression (conjunctive adverb), not one of the seven FANBOYS coordinating conjunctions."},
      {id:"cs057",type:"mc",q:"What is wrong with: 'The hospital is understaffed; but, patient care has not suffered.'?",options:["Do not use a semicolon before a coordinating conjunction — use a comma.","Nothing — it is correct.","'But' should be 'however'.","A comma is missing after 'suffered'."],a:0,exp:"Coordinating conjunctions take a comma before them, not a semicolon. Use: 'understaffed, but patient care'."},
      {id:"cs058",type:"mc",q:"Which pair of sentences forms a compound sentence when joined?",options:["'The tax was introduced.' and 'Revenue increased immediately.'","'Although the tax was introduced.' and 'Revenue increased immediately.'","'The tax that was introduced last year.' and 'Revenue increased.'","'Introducing the tax.' and 'Revenue increased immediately.'"],a:0,exp:"Only two complete independent clauses can form a compound sentence when joined."},
      {id:"cs059",type:"mc",q:"'The old factory was demolished; in its place, a community centre was built.' What is the relationship?",options:["Replacement/sequence","Contrast","Cause","Addition"],a:0,exp:"The semicolon connects two related events: demolition followed by construction."},
      {id:"cs060",type:"mc",q:"Which revision fixes the comma splice: 'The population is growing, resources are becoming scarce.'?",options:["All of the below are correct.","The population is growing, and resources are becoming scarce.","The population is growing; resources are becoming scarce.","The population is growing; consequently, resources are becoming scarce."],a:0,exp:"A comma splice can be fixed by adding a conjunction, using a semicolon, or using a semicolon with a transitional expression."},
      {id:"cs061",type:"mc",q:"What is the role of the semicolon in compound sentences?",options:["It joins two closely related independent clauses without a conjunction.","It introduces a list.","It separates items in a simple list.","It ends a sentence."],a:0,exp:"In compound sentences, the semicolon replaces the comma + conjunction to join related independent clauses."},
      {id:"cs062",type:"mc",q:"'Air quality has improved; ___, respiratory diseases have declined.' Which transitional expression fits?",options:["accordingly","however","on the other hand","nevertheless"],a:0,exp:"'Accordingly' shows a logical result: improved air quality led to fewer respiratory diseases."},
      {id:"cs063",type:"mc",q:"Which sentence type is best for presenting two contrasting viewpoints of equal weight?",options:["Compound sentence","Simple sentence","Complex sentence","Fragment"],a:0,exp:"Compound sentences give equal weight to both clauses, making them ideal for balanced contrasts."},
      {id:"cs064",type:"mc",q:"'The reform was necessary, so it was implemented swiftly.' How many independent clauses are there?",options:["Two","One","Three","None"],a:0,exp:"'The reform was necessary' and 'it was implemented swiftly' are both independent clauses joined by 'so'."},
      {id:"cs065",type:"mc",q:"Which is the correct order for a compound sentence with a transitional expression?",options:["Independent clause; transitional expression, independent clause.","Independent clause, transitional expression; independent clause.","Independent clause transitional expression, independent clause.","Independent clause; transitional expression independent clause."],a:0,exp:"The pattern is: IC1 + semicolon + transitional expression + comma + IC2."},
      {id:"cs066",type:"mc",q:"'Tuition fees have risen sharply; as a result, student debt has reached record levels.' What transitional relationship is shown?",options:["Cause-effect","Contrast","Addition","Sequence"],a:0,exp:"'As a result' shows a cause-effect relationship between rising fees and record debt levels."},
      {id:"cs067",type:"mc",q:"Which is a transitional expression showing addition?",options:["furthermore","however","otherwise","instead"],a:0,exp:"'Furthermore' is a transitional expression meaning 'in addition', used to add information."},
      {id:"cs068",type:"mc",q:"What is wrong with: 'The new policy is effective moreover it is cost-efficient.'?",options:["Missing semicolon before 'moreover' and comma after it.","Nothing — it is correct.","'Moreover' should be 'and'.","A period should replace 'moreover'."],a:0,exp:"Correct form: 'The new policy is effective; moreover, it is cost-efficient.'"},
      {id:"cs069",type:"mc",q:"Which transitional expression means 'in the same way'?",options:["similarly","nevertheless","instead","hence"],a:0,exp:"'Similarly' shows that two things are alike, meaning 'in the same way'."},
      {id:"cs070",type:"mc",q:"How many ways can you form a compound sentence?",options:["Three: comma + FANBOYS, semicolon, semicolon + transitional expression","Two: comma + FANBOYS, semicolon","One: comma + FANBOYS","Four: comma + FANBOYS, semicolon, colon, dash"],a:0,exp:"The three standard methods are: (1) comma + coordinating conjunction, (2) semicolon alone, (3) semicolon + transitional expression + comma."},
      {id:"cs071",type:"mc",q:"'Several studies support this view; in fact, the evidence is overwhelming.' What does 'in fact' express?",options:["Emphasis/strengthening of the previous point","Contrast","Result","Sequence"],a:0,exp:"'In fact' strengthens or emphasises the previous point, adding stronger evidence."},
      {id:"cs072",type:"mc",q:"Which revision creates a compound sentence: 'The rain stopped. The match resumed.'?",options:["The rain stopped, and the match resumed.","When the rain stopped, the match resumed.","After the rain stopped, the match resumed.","The match resumed because the rain stopped."],a:0,exp:"Only option A uses a comma + coordinating conjunction to create a compound sentence. The others create complex sentences."},
      {id:"cs073",type:"mc",q:"'Unemployment is high in rural areas; ___, urban centres face labour shortages.' Which transitional expression fits?",options:["meanwhile","therefore","furthermore","accordingly"],a:0,exp:"'Meanwhile' shows two simultaneous but different situations in rural and urban areas."},
      {id:"cs074",type:"mc",q:"Which sentence is NOT a compound sentence?",options:["Because the economy improved, employment rates rose.","The economy improved, and employment rates rose.","The economy improved; employment rates rose.","The economy improved; consequently, employment rates rose."],a:0,exp:"'Because' creates a complex sentence (dependent + independent clause), not a compound sentence."},
      {id:"cs075",type:"mc",q:"'The regulations were strict; ___, businesses adapted quickly.' Which word shows contrast?",options:["nonetheless","therefore","subsequently","moreover"],a:0,exp:"'Nonetheless' shows contrast: despite strict regulations, businesses adapted."},
      {id:"cs076",type:"error",q:"The government increased funding, however, the programme still failed.",a:"The government increased funding; however, the programme still failed.",exp:"'However' is a transitional expression, not a coordinating conjunction. Use a semicolon before it, not a comma."},
      {id:"cs077",type:"error",q:"Education improves employment prospects, it also strengthens social cohesion.",a:"Education improves employment prospects, and it also strengthens social cohesion.",exp:"Comma splice: two independent clauses need a conjunction. Add 'and' after the comma."},
      {id:"cs078",type:"error",q:"The policy was effective; but it was also expensive.",a:"The policy was effective, but it was also expensive.",exp:"Do not use a semicolon before a coordinating conjunction. Use a comma: 'effective, but it was also expensive.'"},
      {id:"cs079",type:"error",q:"Healthcare spending has risen therefore taxes have increased.",a:"Healthcare spending has risen; therefore, taxes have increased.",exp:"'Therefore' needs a semicolon before it and a comma after it when joining two independent clauses."},
      {id:"cs080",type:"error",q:"The university expanded its campus, it attracted more international students.",a:"The university expanded its campus; as a result, it attracted more international students.",exp:"Comma splice fixed by using a semicolon and an appropriate transitional expression showing result."},
      {id:"cs081",type:"error",q:"Air pollution is a major concern; and the government must address it.",a:"Air pollution is a major concern, and the government must address it.",exp:"Use a comma (not a semicolon) before a coordinating conjunction joining two independent clauses."},
      {id:"cs082",type:"error",q:"The research findings were significant, consequently, they influenced government policy.",a:"The research findings were significant; consequently, they influenced government policy.",exp:"'Consequently' is a transitional expression requiring a semicolon before it, not a comma."},
      {id:"cs083",type:"error",q:"The evidence was clear the jury reached a verdict within an hour.",a:"The evidence was clear, so the jury reached a verdict within an hour.",exp:"Run-on sentence. Add a comma and coordinating conjunction 'so' to show result."},
      {id:"cs084",type:"error",q:"Public transport is efficient, moreover it is environmentally friendly.",a:"Public transport is efficient; moreover, it is environmentally friendly.",exp:"'Moreover' requires a semicolon before it and a comma after it."},
      {id:"cs085",type:"error",q:"The cost of living has increased; but, wages have not kept pace.",a:"The cost of living has increased, but wages have not kept pace.",exp:"Use a comma before 'but' (not a semicolon), and do not place a comma after 'but'."},
      {id:"cs086",type:"error",q:"Obesity rates have risen sharply, this is due to poor dietary habits.",a:"Obesity rates have risen sharply; this is due to poor dietary habits.",exp:"Comma splice. Use a semicolon to join two independent clauses without a conjunction."},
      {id:"cs087",type:"error",q:"The new regulation reduced pollution levels furthermore it saved the industry millions.",a:"The new regulation reduced pollution levels; furthermore, it saved the industry millions.",exp:"Run-on sentence. 'Furthermore' requires a semicolon before it and a comma after it."},
      {id:"cs088",type:"error",q:"Recycling programmes are effective, nevertheless many residents do not participate.",a:"Recycling programmes are effective; nevertheless, many residents do not participate.",exp:"'Nevertheless' is a transitional expression requiring a semicolon before and a comma after."},
      {id:"cs089",type:"error",q:"The study's methodology was sound; and, its conclusions were well-supported.",a:"The study's methodology was sound, and its conclusions were well-supported.",exp:"Use a comma (not semicolon) before 'and', and no comma after the conjunction."},
      {id:"cs090",type:"error",q:"Students need practical skills, they also need theoretical knowledge.",a:"Students need practical skills, and they also need theoretical knowledge.",exp:"Comma splice. Add the coordinating conjunction 'and' to join the two clauses properly."},
      {id:"cs091",type:"error",q:"The population grew rapidly, as a result, housing became scarce.",a:"The population grew rapidly; as a result, housing became scarce.",exp:"'As a result' is a transitional expression. Use a semicolon before it, not a comma."},
      {id:"cs092",type:"error",q:"The government introduced reforms, they were widely praised by experts.",a:"The government introduced reforms, and they were widely praised by experts.",exp:"Comma splice fixed by adding the conjunction 'and'."},
      {id:"cs093",type:"error",q:"Climate change affects food security; it, also impacts water supplies.",a:"Climate change affects food security; it also impacts water supplies.",exp:"No comma should separate the subject 'it' from 'also impacts'. Remove the comma."},
      {id:"cs094",type:"error",q:"The experiment yielded unexpected results, thus the hypothesis was revised.",a:"The experiment yielded unexpected results; thus, the hypothesis was revised.",exp:"'Thus' is a transitional expression requiring a semicolon before and a comma after."},
      {id:"cs095",type:"error",q:"Wages have stagnated for years many workers are seeking second jobs.",a:"Wages have stagnated for years; consequently, many workers are seeking second jobs.",exp:"Run-on sentence. Use a semicolon and a transitional expression to join the clauses."},
      {id:"cs096",type:"error",q:"Online learning is flexible, it requires strong self-discipline however.",a:"Online learning is flexible; however, it requires strong self-discipline.",exp:"'However' should follow a semicolon and be placed at the beginning of the second clause, followed by a comma."},
      {id:"cs097",type:"error",q:"The tax reform benefited the wealthy, on the other hand, it burdened low-income earners.",a:"The tax reform benefited the wealthy; on the other hand, it burdened low-income earners.",exp:"'On the other hand' is a transitional expression requiring a semicolon before it."},
      {id:"cs098",type:"error",q:"Technology evolves rapidly, similarly education must adapt to keep pace.",a:"Technology evolves rapidly; similarly, education must adapt to keep pace.",exp:"'Similarly' is a transitional expression and requires a semicolon before it and a comma after it."},
      {id:"cs099",type:"error",q:"The hospital was underfunded it could not hire enough staff.",a:"The hospital was underfunded, so it could not hire enough staff.",exp:"Run-on sentence. Add a comma + 'so' to show the result of underfunding."},
      {id:"cs100",type:"error",q:"Many students struggle with writing, hence their essays lack coherence.",a:"Many students struggle with writing; hence, their essays lack coherence.",exp:"'Hence' is a transitional expression. Use a semicolon before and a comma after."},
      {id:"cs101",type:"error",q:"The findings were published, in addition the raw data was made available.",a:"The findings were published; in addition, the raw data was made available.",exp:"'In addition' is a transitional expression requiring a semicolon before and a comma after."},
      {id:"cs102",type:"error",q:"Exercise improves physical health; so it also benefits mental well-being.",a:"Exercise improves physical health, so it also benefits mental well-being.",exp:"'So' is a coordinating conjunction and takes a comma before it, not a semicolon."},
      {id:"cs103",type:"error",q:"Public spending must increase, otherwise essential services will deteriorate.",a:"Public spending must increase; otherwise, essential services will deteriorate.",exp:"'Otherwise' is a transitional expression requiring a semicolon before and a comma after."},
      {id:"cs104",type:"error",q:"The economy recovered slowly, meanwhile social inequality widened.",a:"The economy recovered slowly; meanwhile, social inequality widened.",exp:"'Meanwhile' is a transitional expression requiring a semicolon before and a comma after."},
      {id:"cs105",type:"error",q:"Greenhouse gas emissions are rising, for example carbon dioxide levels have increased by 40 percent.",a:"Greenhouse gas emissions are rising; for example, carbon dioxide levels have increased by 40 percent.",exp:"'For example' is a transitional expression and requires a semicolon before and a comma after."},
      {id:"cs106",type:"combine",q:"The government invested in infrastructure. + Thousands of new jobs were created.",a:"The government invested in infrastructure, and thousands of new jobs were created.",exp:"'And' joins two related outcomes. A comma precedes the conjunction before the second independent clause."},
      {id:"cs107",type:"combine",q:"The research was well-funded. + The results were inconclusive.",a:"The research was well-funded, yet the results were inconclusive.",exp:"'Yet' shows unexpected contrast between funding and inconclusive results."},
      {id:"cs108",type:"combine",q:"Carbon emissions continue to rise. + Governments have pledged to reduce them.",a:"Carbon emissions continue to rise; however, governments have pledged to reduce them.",exp:"'However' with semicolon punctuation shows contrast in a compound sentence."},
      {id:"cs109",type:"combine",q:"Vaccination programmes have been expanded. + Disease rates have fallen sharply.",a:"Vaccination programmes have been expanded; consequently, disease rates have fallen sharply.",exp:"'Consequently' shows the result of expanded vaccination programmes."},
      {id:"cs110",type:"combine",q:"The university raised tuition fees. + Student enrolment declined.",a:"The university raised tuition fees; as a result, student enrolment declined.",exp:"'As a result' links the fee increase to the decline in enrolment."},
      {id:"cs111",type:"combine",q:"Air quality has improved in major cities. + Water pollution remains a serious problem.",a:"Air quality has improved in major cities; nevertheless, water pollution remains a serious problem.",exp:"'Nevertheless' shows that water pollution persists despite air quality improvements."},
      {id:"cs112",type:"combine",q:"Mental health services need more funding. + The government has announced budget cuts.",a:"Mental health services need more funding, but the government has announced budget cuts.",exp:"'But' shows contrast between the need and the government's action."},
      {id:"cs113",type:"combine",q:"Technology has transformed communication. + It has also revolutionised education.",a:"Technology has transformed communication; moreover, it has also revolutionised education.",exp:"'Moreover' adds a further area transformed by technology."},
      {id:"cs114",type:"combine",q:"Unemployment has decreased in urban areas. + Rural communities continue to struggle.",a:"Unemployment has decreased in urban areas; in contrast, rural communities continue to struggle.",exp:"'In contrast' highlights the difference between urban and rural employment."},
      {id:"cs115",type:"combine",q:"The policy was well-intentioned. + It failed to achieve measurable results.",a:"The policy was well-intentioned; however, it failed to achieve measurable results.",exp:"'However' introduces a contrast between the good intention and the poor results."},
      {id:"cs116",type:"combine",q:"Healthcare professionals are overworked. + Patient satisfaction scores have declined.",a:"Healthcare professionals are overworked, and patient satisfaction scores have declined.",exp:"'And' connects two related negative developments in healthcare."},
      {id:"cs117",type:"combine",q:"The country must diversify its economy. + It will remain vulnerable to commodity price fluctuations.",a:"The country must diversify its economy; otherwise, it will remain vulnerable to commodity price fluctuations.",exp:"'Otherwise' warns of the consequence of not diversifying."},
      {id:"cs118",type:"combine",q:"Online learning offers flexibility. + Traditional classrooms provide social interaction.",a:"Online learning offers flexibility; on the other hand, traditional classrooms provide social interaction.",exp:"'On the other hand' presents a contrasting advantage of traditional learning."},
      {id:"cs119",type:"combine",q:"The study analysed demographic trends. + It also examined economic indicators.",a:"The study analysed demographic trends; furthermore, it also examined economic indicators.",exp:"'Furthermore' adds a second aspect of the study's analysis."},
      {id:"cs120",type:"combine",q:"Taxes must increase to fund public services. + Many citizens oppose higher taxation.",a:"Taxes must increase to fund public services, but many citizens oppose higher taxation.",exp:"'But' shows the tension between the need for taxes and public opposition."},
      {id:"cs121",type:"combine",q:"The city built new parks and playgrounds. + Community well-being indicators improved.",a:"The city built new parks and playgrounds; subsequently, community well-being indicators improved.",exp:"'Subsequently' shows the positive change that followed the construction."},
      {id:"cs122",type:"combine",q:"Global trade has increased significantly. + Many developing countries have benefited.",a:"Global trade has increased significantly; accordingly, many developing countries have benefited.",exp:"'Accordingly' links increased trade to benefits for developing countries."},
      {id:"cs123",type:"combine",q:"The evidence supports immediate action. + Policymakers have been slow to respond.",a:"The evidence supports immediate action; nonetheless, policymakers have been slow to respond.",exp:"'Nonetheless' shows the slow response despite supporting evidence."},
      {id:"cs124",type:"combine",q:"Digital literacy is essential in the modern economy. + Schools must integrate technology into the curriculum.",a:"Digital literacy is essential in the modern economy; therefore, schools must integrate technology into the curriculum.",exp:"'Therefore' shows the logical conclusion: the importance of digital literacy necessitates curriculum integration."},
      {id:"cs125",type:"combine",q:"Automation has reduced manufacturing costs. + It has increased efficiency across industries.",a:"Automation has reduced manufacturing costs; likewise, it has increased efficiency across industries.",exp:"'Likewise' shows that automation has similarly positive effects on both costs and efficiency."},
      {id:"cs126",type:"combine",q:"The research received widespread acclaim. + Several experts questioned the methodology.",a:"The research received widespread acclaim; however, several experts questioned the methodology.",exp:"'However' introduces a contrasting reaction to the research."},
      {id:"cs127",type:"combine",q:"Childhood obesity has become a major public health concern. + Schools have introduced healthier lunch menus.",a:"Childhood obesity has become a major public health concern; in response, schools have introduced healthier lunch menus.",exp:"'In response' shows the action taken to address the concern."},
      {id:"cs128",type:"combine",q:"Renewable energy adoption is accelerating. + Fossil fuel companies are diversifying their portfolios.",a:"Renewable energy adoption is accelerating; meanwhile, fossil fuel companies are diversifying their portfolios.",exp:"'Meanwhile' shows two simultaneous developments in the energy sector."},
      {id:"cs129",type:"combine",q:"The city expanded its recycling programme. + Household waste sent to landfill decreased by 30 percent.",a:"The city expanded its recycling programme, and household waste sent to landfill decreased by 30 percent.",exp:"'And' connects the programme expansion to its positive outcome."},
      {id:"cs130",type:"combine",q:"Immigration enriches cultural diversity. + It strengthens the labour force.",a:"Immigration enriches cultural diversity; in addition, it strengthens the labour force.",exp:"'In addition' adds a second benefit of immigration."},
      {id:"cs131",type:"combine",q:"Public health campaigns raised awareness of the disease. + Screening rates increased dramatically.",a:"Public health campaigns raised awareness of the disease; as a result, screening rates increased dramatically.",exp:"'As a result' shows that raised awareness led to increased screening."},
      {id:"cs132",type:"combine",q:"The budget was reduced by 20 percent. + The organisation maintained all essential services.",a:"The budget was reduced by 20 percent; nonetheless, the organisation maintained all essential services.",exp:"'Nonetheless' shows that services were maintained despite significant budget cuts."},
      {id:"cs133",type:"combine",q:"The new curriculum emphasises practical skills. + Employers have reported greater satisfaction with graduates.",a:"The new curriculum emphasises practical skills; consequently, employers have reported greater satisfaction with graduates.",exp:"'Consequently' links the practical curriculum to employer satisfaction."},
      {id:"cs134",type:"combine",q:"Access to clean water remains limited in some regions. + Waterborne diseases continue to claim lives.",a:"Access to clean water remains limited in some regions; as a result, waterborne diseases continue to claim lives.",exp:"'As a result' links limited water access to the persistence of waterborne diseases."},
      {id:"cs135",type:"combine",q:"The government offered tax incentives for businesses. + Foreign investment increased significantly.",a:"The government offered tax incentives for businesses; consequently, foreign investment increased significantly.",exp:"'Consequently' shows the result of tax incentives on foreign investment."},
      {id:"cs136",type:"combine",q:"Early intervention programmes are effective. + They should receive greater funding.",a:"Early intervention programmes are effective; therefore, they should receive greater funding.",exp:"'Therefore' draws the logical conclusion from effectiveness to funding."},
      {id:"cs137",type:"combine",q:"The study focused on urban populations. + Rural perspectives were not included.",a:"The study focused on urban populations; as a result, rural perspectives were not included.",exp:"'As a result' shows that the urban focus led to rural exclusion."},
      {id:"cs138",type:"combine",q:"Social media has democratised information access. + It has also enabled the spread of misinformation.",a:"Social media has democratised information access; however, it has also enabled the spread of misinformation.",exp:"'However' contrasts the positive and negative effects of social media."},
      {id:"cs139",type:"combine",q:"The hospital introduced telemedicine services. + Patient satisfaction improved among rural communities.",a:"The hospital introduced telemedicine services, and patient satisfaction improved among rural communities.",exp:"'And' joins the introduction of services to the improvement in satisfaction."},
      {id:"cs140",type:"combine",q:"Standardised testing provides measurable data. + It may not capture the full range of student abilities.",a:"Standardised testing provides measurable data; nevertheless, it may not capture the full range of student abilities.",exp:"'Nevertheless' shows a limitation despite the advantage of measurable data."},
      {id:"cs141",type:"transform",q:"Education improves economic outcomes. Education also promotes social equality. [Join with a semicolon and transitional expression]",a:"Education improves economic outcomes; furthermore, it also promotes social equality.",exp:"'Furthermore' adds information. Semicolon + transitional expression + comma is the correct pattern."},
      {id:"cs142",type:"transform",q:"The government cut healthcare spending. Patient outcomes deteriorated. [Join with a comma and coordinating conjunction]",a:"The government cut healthcare spending, so patient outcomes deteriorated.",exp:"'So' shows the result. Comma + coordinating conjunction joins the two clauses."},
      {id:"cs143",type:"transform",q:"The research methodology was flawed. The conclusions may still be valid. [Join with a semicolon and transitional expression]",a:"The research methodology was flawed; nevertheless, the conclusions may still be valid.",exp:"'Nevertheless' shows concession: validity despite flawed methodology."},
      {id:"cs144",type:"transform",q:"Automation threatens traditional jobs. It creates new opportunities in technology. [Join with a comma and coordinating conjunction]",a:"Automation threatens traditional jobs, but it creates new opportunities in technology.",exp:"'But' shows contrast between the threat and the new opportunities."},
      {id:"cs145",type:"transform",q:"Air quality in the city improved. Respiratory hospital admissions decreased. [Join with a semicolon and transitional expression]",a:"Air quality in the city improved; consequently, respiratory hospital admissions decreased.",exp:"'Consequently' shows the result of improved air quality on hospital admissions."},
      {id:"cs146",type:"transform",q:"Many students prefer online learning. Others find it isolating. [Join with a semicolon alone]",a:"Many students prefer online learning; others find it isolating.",exp:"A semicolon alone can join two closely related, contrasting independent clauses."},
      {id:"cs147",type:"transform",q:"The evidence supports the theory. Further research is needed. [Join with a semicolon and transitional expression]",a:"The evidence supports the theory; however, further research is needed.",exp:"'However' introduces the caveat that more research is still necessary."},
      {id:"cs148",type:"transform",q:"Water scarcity is a growing problem. Desalination technology is advancing rapidly. [Join with a comma and coordinating conjunction]",a:"Water scarcity is a growing problem, but desalination technology is advancing rapidly.",exp:"'But' contrasts the problem with the advancing solution."},
      {id:"cs149",type:"transform",q:"The school adopted a new curriculum. Student engagement increased markedly. [Join with a semicolon and transitional expression]",a:"The school adopted a new curriculum; as a result, student engagement increased markedly.",exp:"'As a result' links the new curriculum to increased engagement."},
      {id:"cs150",type:"transform",q:"Funding was withdrawn from the arts programme. Community participation in cultural events declined. [Join with a semicolon and transitional expression]",a:"Funding was withdrawn from the arts programme; consequently, community participation in cultural events declined.",exp:"'Consequently' shows the negative result of funding withdrawal on community participation."},
      {id:"cs151",type:"transform",q:"The policy has been praised by economists. Ordinary citizens have criticised it. [Join with a comma and coordinating conjunction]",a:"The policy has been praised by economists, yet ordinary citizens have criticised it.",exp:"'Yet' shows the unexpected contrast between expert praise and public criticism."},
      {id:"cs152",type:"transform",q:"Technology connects people across continents. It sometimes weakens local community bonds. [Join with a semicolon and transitional expression]",a:"Technology connects people across continents; on the other hand, it sometimes weakens local community bonds.",exp:"'On the other hand' presents the opposing effect of technology on relationships."},
      {id:"cs153",type:"transform",q:"Electric vehicle sales have surged. Charging infrastructure remains inadequate. [Join with a comma and coordinating conjunction]",a:"Electric vehicle sales have surged, but charging infrastructure remains inadequate.",exp:"'But' contrasts the surge in sales with inadequate infrastructure."},
      {id:"cs154",type:"transform",q:"The hospital upgraded its facilities. It hired additional specialist staff. [Join with a semicolon and transitional expression]",a:"The hospital upgraded its facilities; moreover, it hired additional specialist staff.",exp:"'Moreover' adds a second improvement alongside the facility upgrade."},
      {id:"cs155",type:"transform",q:"Drought conditions have worsened across the region. Water restrictions have been imposed. [Join with a semicolon and transitional expression]",a:"Drought conditions have worsened across the region; accordingly, water restrictions have been imposed.",exp:"'Accordingly' shows the response to worsening drought conditions."},
      {id:"cs156",type:"transform",q:"Small businesses drive economic innovation. They also create the majority of new jobs. [Join with a semicolon and transitional expression]",a:"Small businesses drive economic innovation; in addition, they also create the majority of new jobs.",exp:"'In addition' adds a second contribution of small businesses."},
      {id:"cs157",type:"transform",q:"The study was published in a top journal. Its impact was felt across multiple disciplines. [Join with a comma and coordinating conjunction]",a:"The study was published in a top journal, and its impact was felt across multiple disciplines.",exp:"'And' connects publication to its widespread impact."},
      {id:"cs158",type:"transform",q:"Governments must act on climate change. Future generations will face severe consequences. [Join with a semicolon and transitional expression]",a:"Governments must act on climate change; otherwise, future generations will face severe consequences.",exp:"'Otherwise' warns of the consequences of government inaction."},
      {id:"cs159",type:"transform",q:"Immigration policies have become more restrictive. Many industries face labour shortages. [Join with a semicolon and transitional expression]",a:"Immigration policies have become more restrictive; as a result, many industries face labour shortages.",exp:"'As a result' links restrictive policies to labour shortages."},
      {id:"cs160",type:"transform",q:"The new tax was unpopular. The government decided to implement it regardless. [Join with a comma and coordinating conjunction]",a:"The new tax was unpopular, but the government decided to implement it regardless.",exp:"'But' shows contrast between public opinion and the government's decision."},
      {id:"cs161",type:"identify",q:"The government increased taxes, and public services improved.",a:"Compound sentence (comma + coordinating conjunction 'and')",exp:"Two independent clauses joined by a comma and the coordinating conjunction 'and' form a compound sentence."},
      {id:"cs162",type:"identify",q:"Emissions have risen sharply; consequently, climate change has accelerated.",a:"Compound sentence (semicolon + transitional expression 'consequently')",exp:"Two independent clauses joined by a semicolon and the transitional expression 'consequently' form a compound sentence."},
      {id:"cs163",type:"identify",q:"The research was comprehensive; the results were reliable.",a:"Compound sentence (semicolon)",exp:"Two independent clauses joined by a semicolon alone form a compound sentence."},
      {id:"cs164",type:"identify",q:"Healthcare spending has increased, yet outcomes have not improved.",a:"Compound sentence (comma + coordinating conjunction 'yet')",exp:"Two independent clauses joined by a comma and 'yet' form a compound sentence."},
      {id:"cs165",type:"identify",q:"The policy was effective; moreover, it was cost-efficient.",a:"Compound sentence (semicolon + transitional expression 'moreover')",exp:"Two independent clauses joined by a semicolon and 'moreover' form a compound sentence."},
      {id:"cs166",type:"identify",q:"Students must submit their essays on time, or they will receive a penalty.",a:"Compound sentence (comma + coordinating conjunction 'or')",exp:"Two independent clauses joined by a comma and the coordinating conjunction 'or' form a compound sentence."},
      {id:"cs167",type:"identify",q:"Renewable energy is expanding rapidly; however, fossil fuels still dominate the global energy mix.",a:"Compound sentence (semicolon + transitional expression 'however')",exp:"Two independent clauses joined by a semicolon and 'however' form a compound sentence."},
      {id:"cs168",type:"identify",q:"Education is a right, and it must be accessible to all citizens.",a:"Compound sentence (comma + coordinating conjunction 'and')",exp:"Two independent clauses joined by a comma and 'and' form a compound sentence."},
      {id:"cs169",type:"identify",q:"The experiment failed, so the hypothesis was revised.",a:"Compound sentence (comma + coordinating conjunction 'so')",exp:"Two independent clauses joined by a comma and 'so' form a compound sentence."},
      {id:"cs170",type:"identify",q:"Public transport is affordable; in contrast, private vehicle ownership is expensive.",a:"Compound sentence (semicolon + transitional expression 'in contrast')",exp:"Two independent clauses joined by a semicolon and 'in contrast' form a compound sentence."}
    ]
  },

  complexSentences: {
    title: "Complex Sentences",
    theory: "A complex sentence has one independent clause and at least one dependent clause (adverbial, relative, or noun clause). The dependent clause cannot stand alone. If the dependent clause comes first, use a comma after it.",
    exercises: [
      {id:"cx001",type:"fill",q:"Students ___ study regularly tend to achieve higher grades in their examinations.",a:"who",exp:"'Who' introduces a relative clause modifying 'students'. It is used for people."},
      {id:"cx002",type:"fill",q:"The policy ___ was introduced last year has significantly reduced carbon emissions.",a:"that",exp:"'That' introduces a restrictive relative clause identifying which policy is meant."},
      {id:"cx003",type:"fill",q:"The university, ___ was founded in 1850, has a strong reputation for research.",a:"which",exp:"'Which' introduces a non-restrictive relative clause adding extra information about the university. Commas set off the clause."},
      {id:"cx004",type:"fill",q:"Researchers ___ findings have been published in top journals receive more funding.",a:"whose",exp:"'Whose' shows possession, introducing a relative clause about the researchers' findings."},
      {id:"cx005",type:"fill",q:"The city ___ the conference was held has excellent transport links.",a:"where",exp:"'Where' introduces a relative clause of place, modifying 'the city'."},
      {id:"cx006",type:"fill",q:"The government announced ___ it would invest heavily in renewable energy.",a:"that",exp:"'That' introduces a noun clause functioning as the object of 'announced'."},
      {id:"cx007",type:"fill",q:"___ the economy will recover depends on several factors.",a:"Whether",exp:"'Whether' introduces a noun clause functioning as the subject of the sentence."},
      {id:"cx008",type:"fill",q:"The researchers discovered ___ the treatment was more effective than expected.",a:"that",exp:"'That' introduces a noun clause as the object of 'discovered'."},
      {id:"cx009",type:"fill",q:"___ causes climate change is a topic of extensive scientific research.",a:"What",exp:"'What' introduces a noun clause functioning as the subject, meaning 'the thing that'."},
      {id:"cx010",type:"fill",q:"The teacher explained ___ students should approach the writing task.",a:"how",exp:"'How' introduces a noun clause as the object of 'explained', describing the method."},
      {id:"cx011",type:"fill",q:"The report, ___ was released yesterday, highlights the impact of urbanisation on biodiversity.",a:"which",exp:"'Which' introduces a non-restrictive relative clause providing additional information about the report."},
      {id:"cx012",type:"fill",q:"Citizens ___ do not vote cannot complain about government decisions.",a:"who",exp:"'Who' introduces a restrictive relative clause identifying which citizens are meant."},
      {id:"cx013",type:"fill",q:"The reason ___ the policy failed was inadequate implementation.",a:"why",exp:"'Why' introduces a relative clause of reason, modifying 'the reason'. 'That' is also acceptable here."},
      {id:"cx014",type:"fill",q:"The year ___ the new curriculum was introduced saw dramatic improvements in test scores.",a:"when",exp:"'When' introduces a relative clause of time, modifying 'the year'."},
      {id:"cx015",type:"fill",q:"It is widely recognised ___ education is fundamental to economic development.",a:"that",exp:"'That' introduces a noun clause following 'it is recognised'. 'It' is a dummy subject."},
      {id:"cx016",type:"fill",q:"___ surprised the researchers was the speed of the recovery.",a:"What",exp:"'What' introduces a noun clause as the subject, meaning 'the thing that surprised them'."},
      {id:"cx017",type:"fill",q:"The organisation provides support to families ___ children have special educational needs.",a:"whose",exp:"'Whose' introduces a relative clause showing possession: the families' children."},
      {id:"cx018",type:"fill",q:"The hospital ___ my grandmother was treated has been renovated.",a:"where",exp:"'Where' introduces a relative clause of place, modifying 'the hospital'."},
      {id:"cx019",type:"fill",q:"Nobody knows ___ the government will change its immigration policy.",a:"when",exp:"'When' introduces a noun clause as the object of 'knows', referring to an unknown time."},
      {id:"cx020",type:"fill",q:"The study demonstrated ___ early intervention programmes produce long-term benefits.",a:"that",exp:"'That' introduces a noun clause as the object of 'demonstrated'."},
      {id:"cx021",type:"fill",q:"The professor ___ taught the course has retired after thirty years of service.",a:"who",exp:"'Who' introduces a restrictive relative clause identifying which professor."},
      {id:"cx022",type:"fill",q:"The data ___ the team collected over three years was analysed using advanced statistical methods.",a:"that",exp:"'That' introduces a restrictive relative clause specifying which data."},
      {id:"cx023",type:"fill",q:"Scientists are investigating ___ rising sea levels will affect coastal communities.",a:"how",exp:"'How' introduces a noun clause as the object of 'investigating', describing the manner of impact."},
      {id:"cx024",type:"fill",q:"The school, ___ principal recently won a national award, is known for its innovative teaching methods.",a:"whose",exp:"'Whose' introduces a non-restrictive relative clause showing possession. Commas set off the clause."},
      {id:"cx025",type:"fill",q:"___ the experiment will succeed remains uncertain at this stage.",a:"Whether",exp:"'Whether' introduces a noun clause functioning as the subject of the sentence."},
      {id:"cx026",type:"fill",q:"The community centre ___ was built last year already serves over two thousand residents.",a:"that",exp:"'That' introduces a restrictive relative clause identifying which community centre."},
      {id:"cx027",type:"fill",q:"Economists cannot predict ___ the recession will end.",a:"when",exp:"'When' introduces a noun clause as the object of 'predict'."},
      {id:"cx028",type:"fill",q:"The factory, ___ employed over five hundred workers, was closed due to environmental violations.",a:"which",exp:"'Which' introduces a non-restrictive relative clause adding information about the factory."},
      {id:"cx029",type:"fill",q:"___ is clear from the evidence is that immediate action is needed.",a:"What",exp:"'What' introduces a noun clause as the subject, meaning 'the thing that is clear'."},
      {id:"cx030",type:"fill",q:"The region ___ the earthquake struck has received substantial international aid.",a:"where",exp:"'Where' introduces a relative clause of place, modifying 'the region'."},
      {id:"cx031",type:"fill",q:"Experts disagree about ___ genetically modified crops should be widely cultivated.",a:"whether",exp:"'Whether' introduces a noun clause as the object of 'disagree about'."},
      {id:"cx032",type:"fill",q:"The researchers analysed the period ___ social media usage increased most rapidly.",a:"when",exp:"'When' introduces a relative clause of time, modifying 'the period'. 'During which' also works."},
      {id:"cx033",type:"fill",q:"The charity, ___ mission is to reduce poverty, has expanded to fifteen countries.",a:"whose",exp:"'Whose' introduces a non-restrictive relative clause showing the charity's possession of its mission."},
      {id:"cx034",type:"fill",q:"Many people believe ___ artificial intelligence will fundamentally transform the labour market.",a:"that",exp:"'That' introduces a noun clause as the object of 'believe'."},
      {id:"cx035",type:"fill",q:"The hospital ___ specialises in cardiac care has the lowest mortality rates in the state.",a:"that",exp:"'That' introduces a restrictive relative clause identifying which hospital."},
      {id:"cx036",type:"fill",q:"The government must decide ___ to allocate the remaining budget surplus.",a:"how",exp:"'How' introduces a noun clause as the object of 'decide', describing the method of allocation."},
      {id:"cx037",type:"fill",q:"The programme ___ was designed to reduce youth unemployment has exceeded all expectations.",a:"that",exp:"'That' introduces a restrictive relative clause specifying which programme."},
      {id:"cx038",type:"fill",q:"Professor Chen, ___ research has been cited thousands of times, will deliver the keynote address.",a:"whose",exp:"'Whose' introduces a non-restrictive relative clause showing possession of the research."},
      {id:"cx039",type:"fill",q:"The survey revealed ___ most citizens support investment in public education.",a:"that",exp:"'That' introduces a noun clause as the object of 'revealed'."},
      {id:"cx040",type:"fill",q:"The auditorium ___ the graduation ceremony takes place can accommodate three thousand guests.",a:"where",exp:"'Where' introduces a relative clause of place, modifying 'the auditorium'."},
      {id:"cx041",type:"mc",q:"Which sentence is a complex sentence?",options:["Because the evidence was compelling, the policy was adopted.","The evidence was compelling, and the policy was adopted.","The evidence was compelling; the policy was adopted.","The evidence was compelling. The policy was adopted."],a:0,exp:"A complex sentence has an independent clause and a dependent clause. 'Because' creates a dependent clause."},
      {id:"cx042",type:"mc",q:"What is a dependent clause?",options:["A clause that cannot stand alone as a sentence.","A clause that can stand alone as a sentence.","A clause with no verb.","A clause that uses coordinating conjunctions."],a:0,exp:"A dependent clause has a subject and verb but begins with a subordinator, so it cannot stand alone."},
      {id:"cx043",type:"mc",q:"Which word introduces a relative clause for people?",options:["who","which","where","when"],a:0,exp:"'Who' introduces relative clauses that modify nouns referring to people."},
      {id:"cx044",type:"mc",q:"When does a complex sentence need a comma?",options:["When the dependent clause comes before the independent clause.","Always.","Never.","When the independent clause comes first."],a:0,exp:"If the dependent clause comes first, place a comma between it and the independent clause."},
      {id:"cx045",type:"mc",q:"Which is a non-restrictive relative clause?",options:["The report, which was published last month, recommends policy changes.","The report that was published last month recommends policy changes.","The report published last month recommends policy changes.","The published report recommends policy changes."],a:0,exp:"Non-restrictive clauses use 'which' and are set off by commas. They add extra, non-essential information."},
      {id:"cx046",type:"mc",q:"What type of clause is 'that education improves economic outcomes' in 'Research shows that education improves economic outcomes'?",options:["Noun clause (object)","Relative clause","Adverbial clause","Independent clause"],a:0,exp:"'That education improves economic outcomes' functions as a noun clause, serving as the object of 'shows'."},
      {id:"cx047",type:"mc",q:"Which sentence correctly punctuates a complex sentence?",options:["Although the study had limitations, its findings were valuable.","Although the study had limitations its findings were valuable.","Although, the study had limitations, its findings were valuable.","The study had limitations, although its findings were valuable."],a:0,exp:"When the dependent clause comes first, use a comma after it. Option D is also acceptable but typically has no comma."},
      {id:"cx048",type:"mc",q:"What is the function of 'where' in: 'The region where the study was conducted has a diverse population'?",options:["It introduces a relative clause of place.","It introduces a noun clause.","It introduces an adverbial clause.","It is a coordinating conjunction."],a:0,exp:"'Where' introduces a relative clause modifying 'the region', specifying which region."},
      {id:"cx049",type:"mc",q:"Which word introduces a noun clause meaning 'the thing that'?",options:["what","which","who","where"],a:0,exp:"'What' can introduce a noun clause meaning 'the thing that': 'What matters most is education.'"},
      {id:"cx050",type:"mc",q:"Identify the dependent clause: 'The government, which was recently elected, promised to reform healthcare.'",options:["which was recently elected","The government promised","to reform healthcare","The government promised to reform healthcare"],a:0,exp:"'Which was recently elected' is a non-restrictive relative clause providing extra information about the government."},
      {id:"cx051",type:"mc",q:"What type of dependent clause is: 'because the evidence was overwhelming'?",options:["Adverbial clause (cause/reason)","Noun clause","Relative clause","Independent clause"],a:0,exp:"'Because' introduces an adverbial clause showing cause/reason."},
      {id:"cx052",type:"mc",q:"Which is correct?",options:["Students who study hard tend to succeed.","Students, who study hard, tend to succeed.","Students, who study hard tend to succeed.","Students who study hard, tend to succeed."],a:0,exp:"This is a restrictive relative clause (identifying which students), so no commas are needed."},
      {id:"cx053",type:"mc",q:"'Whether the policy will succeed is uncertain.' What is the function of the noun clause?",options:["Subject of the sentence","Object of the verb","Complement","Adverbial modifier"],a:0,exp:"'Whether the policy will succeed' is a noun clause functioning as the subject of the verb 'is'."},
      {id:"cx054",type:"mc",q:"When should you use 'which' instead of 'that' in a relative clause?",options:["In non-restrictive clauses (extra information, with commas)","In restrictive clauses","Both are always interchangeable","'Which' is for people only"],a:0,exp:"Use 'which' in non-restrictive clauses (set off by commas). Use 'that' in restrictive clauses (no commas)."},
      {id:"cx055",type:"mc",q:"Identify the complex sentence:",options:["If the funding is approved, the project will begin next year.","The funding was approved, and the project will begin next year.","The funding was approved; the project will begin next year.","The project will begin next year with approved funding."],a:0,exp:"'If' creates a dependent clause, making this a complex sentence with one dependent and one independent clause."},
      {id:"cx056",type:"mc",q:"What type of clause is 'whose research has influenced policy' in 'The professor whose research has influenced policy will speak at the conference'?",options:["Relative clause (possessive)","Noun clause","Adverbial clause","Independent clause"],a:0,exp:"'Whose' introduces a possessive relative clause modifying 'the professor'."},
      {id:"cx057",type:"mc",q:"Which sentence uses a noun clause as the subject?",options:["What the government decides will affect millions of people.","The government will decide what affects millions of people.","The decision that affects millions was made yesterday.","Millions of people will be affected by the decision."],a:0,exp:"'What the government decides' is a noun clause functioning as the subject of 'will affect'."},
      {id:"cx058",type:"mc",q:"'The school that implemented the new programme saw improved results.' Is this clause restrictive or non-restrictive?",options:["Restrictive — it identifies which school (no commas, uses 'that').","Non-restrictive — it adds extra information.","Neither — it is an independent clause.","It is an adverbial clause."],a:0,exp:"'That' with no commas indicates a restrictive relative clause that identifies which specific school."},
      {id:"cx059",type:"mc",q:"How many dependent clauses can a complex sentence have?",options:["One or more","Exactly one","Exactly two","None"],a:0,exp:"A complex sentence has at least one dependent clause but can have more than one."},
      {id:"cx060",type:"mc",q:"Which is correct?",options:["The study, which involved 500 participants, produced reliable results.","The study which involved 500 participants produced reliable results.","The study, that involved 500 participants, produced reliable results.","The study, which involved 500 participants produced reliable results."],a:0,exp:"Non-restrictive clauses use 'which' (not 'that') and require commas both before and after the clause."},
      {id:"cx061",type:"mc",q:"What does the dependent clause do in: 'Scientists believe that the ozone layer is recovering.'?",options:["It acts as the object of 'believe' (noun clause).","It modifies 'scientists' (relative clause).","It shows time (adverbial clause).","It is an independent clause."],a:0,exp:"'That the ozone layer is recovering' is a noun clause functioning as the direct object of 'believe'."},
      {id:"cx062",type:"mc",q:"Which type of dependent clause answers the question 'why'?",options:["Adverbial clause of reason/cause","Noun clause","Relative clause","Adverbial clause of time"],a:0,exp:"Adverbial clauses of reason/cause (with 'because', 'since', 'as') answer the question 'why'."},
      {id:"cx063",type:"mc",q:"'The area where deforestation has been most severe requires urgent intervention.' What type of clause is 'where deforestation has been most severe'?",options:["Relative clause of place","Noun clause","Adverbial clause","Independent clause"],a:0,exp:"'Where' introduces a relative clause modifying 'the area', specifying which area."},
      {id:"cx064",type:"mc",q:"What is wrong with: 'The policy that, was introduced last year, has been effective.'?",options:["Commas should not be used with restrictive 'that' clauses.","Nothing — it is correct.","'That' should be 'which'.","The verb is wrong."],a:0,exp:"Restrictive relative clauses with 'that' do not take commas. Remove the commas."},
      {id:"cx065",type:"mc",q:"Which sentence has a noun clause as a complement?",options:["The problem is that resources are insufficient.","The problem that affects us is resource scarcity.","The problem, which is serious, requires attention.","Resources are insufficient because of the problem."],a:0,exp:"'That resources are insufficient' is a noun clause functioning as the subject complement after 'is'."},
      {id:"cx066",type:"mc",q:"'Researchers hope that the new treatment will be effective.' Can 'that' be omitted?",options:["Yes — 'that' can be omitted in informal contexts when it introduces an object clause.","No — 'that' is always required.","Only in questions.","Only in negative sentences."],a:0,exp:"When 'that' introduces a noun clause as the object (after verbs like 'hope', 'believe', 'think'), it can often be omitted."},
      {id:"cx067",type:"mc",q:"What is the difference between a complex and a compound-complex sentence?",options:["A complex sentence has one independent clause; a compound-complex has at least two.","There is no difference.","A compound-complex has no dependent clauses.","A complex sentence always uses semicolons."],a:0,exp:"A complex sentence has one independent + one or more dependent clauses. A compound-complex has two or more independent + one or more dependent clauses."},
      {id:"cx068",type:"mc",q:"'How the disease spreads is not fully understood.' What is the function of 'how the disease spreads'?",options:["Subject (noun clause)","Object (noun clause)","Adverbial clause","Relative clause"],a:0,exp:"'How the disease spreads' is a noun clause functioning as the subject of 'is not fully understood'."},
      {id:"cx069",type:"mc",q:"Which relative pronoun shows possession?",options:["whose","who","which","that"],a:0,exp:"'Whose' is the possessive relative pronoun: 'the researcher whose study was published'."},
      {id:"cx070",type:"mc",q:"Identify the type of dependent clause in: 'After the reforms were implemented, economic growth accelerated.'",options:["Adverbial clause of time","Noun clause","Relative clause","None — it is independent"],a:0,exp:"'After the reforms were implemented' is an adverbial clause of time, answering 'when'."},
      {id:"cx071",type:"mc",q:"Which sentence correctly uses 'whom'?",options:["The candidate whom the committee selected has extensive experience.","The candidate whom selected has extensive experience.","The candidate whom the committee has extensive experience.","Whom the candidate selected has extensive experience."],a:0,exp:"'Whom' is used as the object of the verb in the relative clause: 'the committee selected whom (the candidate)'."},
      {id:"cx072",type:"mc",q:"'It is essential that every citizen has access to healthcare.' What type of clause follows 'it is essential'?",options:["Noun clause (subject complement — 'it' is a dummy subject)","Relative clause","Adverbial clause","Independent clause"],a:0,exp:"'That every citizen has access to healthcare' is a noun clause. 'It' is a dummy subject and the noun clause is the true subject."},
      {id:"cx073",type:"mc",q:"In academic writing, which type of sentence should be used most frequently?",options:["A mix of simple, compound, and complex sentences","Only complex sentences","Only simple sentences","Only compound sentences"],a:0,exp:"Academic writing benefits from sentence variety. A mix of types creates readable, sophisticated prose."},
      {id:"cx074",type:"mc",q:"What error does this sentence contain: 'The study which findings were groundbreaking has been widely cited.'?",options:["'Which' should be 'whose' (to show possession).","No error.","'Which' should be 'that'.","A comma is missing."],a:0,exp:"'Whose' is needed to show possession: 'The study whose findings were groundbreaking'."},
      {id:"cx075",type:"mc",q:"'Nobody knows where the missing data is stored.' What is the dependent clause?",options:["where the missing data is stored (noun clause)","Nobody knows (independent clause)","the missing data (noun phrase)","is stored (verb phrase)"],a:0,exp:"'Where the missing data is stored' is a noun clause functioning as the object of 'knows'."},
      {id:"cx076",type:"error",q:"The policy which was introduced last year has been very effective in reducing emissions.",a:"The policy that was introduced last year has been very effective in reducing emissions.",exp:"This is a restrictive clause (identifying which policy), so use 'that' without commas. Alternatively, add commas with 'which' if the information is non-essential."},
      {id:"cx077",type:"error",q:"Because the government increased funding, so educational outcomes improved.",a:"Because the government increased funding, educational outcomes improved.",exp:"'Because' and 'so' cannot be used together. Remove 'so' — 'because' already introduces the reason."},
      {id:"cx078",type:"error",q:"The researcher who's study was published last year has been promoted.",a:"The researcher whose study was published last year has been promoted.",exp:"'Whose' (possessive relative pronoun) is needed, not 'who's' (contraction of 'who is')."},
      {id:"cx079",type:"error",q:"Although the data was comprehensive. The conclusions were still questioned.",a:"Although the data was comprehensive, the conclusions were still questioned.",exp:"A dependent clause ('although...') cannot stand alone. Join it to the independent clause with a comma."},
      {id:"cx080",type:"error",q:"Students which perform well in examinations receive scholarships.",a:"Students who perform well in examinations receive scholarships.",exp:"Use 'who' (not 'which') for people."},
      {id:"cx081",type:"error",q:"The government announced that it will increased spending on healthcare.",a:"The government announced that it would increase spending on healthcare.",exp:"After 'announced' (past tense), use 'would increase' (not 'will increased') for reported speech."},
      {id:"cx082",type:"error",q:"The city, that was recently named the most liveable in Australia, attracts many immigrants.",a:"The city, which was recently named the most liveable in Australia, attracts many immigrants.",exp:"Non-restrictive relative clauses (with commas) use 'which', not 'that'."},
      {id:"cx083",type:"error",q:"What is the government going to do about climate change is the question on everyone's mind.",a:"What the government is going to do about climate change is the question on everyone's mind.",exp:"Noun clauses use statement word order (subject + verb), not question word order."},
      {id:"cx084",type:"error",q:"The hospital where was built in 1990 needs urgent renovation.",a:"The hospital that was built in 1990 needs urgent renovation.",exp:"'Where' indicates place, but 'the hospital' is the subject being described. Use 'that' or 'which' for the relative clause."},
      {id:"cx085",type:"error",q:"Because of the policy was unpopular, the government revised it.",a:"Because the policy was unpopular, the government revised it.",exp:"'Because' introduces a full clause (subject + verb). 'Because of' takes a noun phrase. Here a clause follows."},
      {id:"cx086",type:"error",q:"The reason because the project failed was poor management.",a:"The reason why the project failed was poor management.",exp:"Use 'the reason why' or 'the reason that', not 'the reason because'. 'Because' is redundant with 'reason'."},
      {id:"cx087",type:"error",q:"Although the study was well-funded, however, it produced inconclusive results.",a:"Although the study was well-funded, it produced inconclusive results.",exp:"'Although' and 'however' are both concessive. Using both is redundant. Remove 'however'."},
      {id:"cx088",type:"error",q:"The professor whom teaches advanced economics will retire next year.",a:"The professor who teaches advanced economics will retire next year.",exp:"'Who' is the subject of 'teaches'. 'Whom' is used as an object, not a subject."},
      {id:"cx089",type:"error",q:"It is widely believed, that technology will transform the education sector.",a:"It is widely believed that technology will transform the education sector.",exp:"No comma should separate the main clause from a 'that' noun clause."},
      {id:"cx090",type:"error",q:"The students whose submitted their assignments on time received full marks.",a:"The students who submitted their assignments on time received full marks.",exp:"'Who' is the subject of 'submitted'. 'Whose' shows possession and is incorrect here."},
      {id:"cx091",type:"error",q:"Researchers discovered that air quality have improved significantly since 2010.",a:"Researchers discovered that air quality has improved significantly since 2010.",exp:"'Air quality' is singular (uncountable), so use 'has' not 'have'."},
      {id:"cx092",type:"error",q:"The country which population exceeds one billion faces enormous infrastructure challenges.",a:"The country whose population exceeds one billion faces enormous infrastructure challenges.",exp:"'Whose' is the possessive relative pronoun showing the country's population. 'Which' cannot show possession."},
      {id:"cx093",type:"error",q:"Nobody knows that when the new regulations will take effect.",a:"Nobody knows when the new regulations will take effect.",exp:"'When' introduces the noun clause directly. 'That' before 'when' is redundant and incorrect."},
      {id:"cx094",type:"error",q:"The research centre, that was established in 2005, has produced over 200 publications.",a:"The research centre, which was established in 2005, has produced over 200 publications.",exp:"Non-restrictive relative clauses (set off by commas) require 'which', not 'that'."},
      {id:"cx095",type:"error",q:"Even though she studied very hard, but she did not pass the examination.",a:"Even though she studied very hard, she did not pass the examination.",exp:"'Even though' and 'but' both signal contrast. Remove 'but' — 'even though' already introduces the concession."},
      {id:"cx096",type:"error",q:"The programme that it was designed for low-income families has been expanded.",a:"The programme that was designed for low-income families has been expanded.",exp:"In a relative clause, 'that' replaces the subject. Adding 'it' creates a redundant pronoun."},
      {id:"cx097",type:"error",q:"What does the government plan to do about healthcare is unclear.",a:"What the government plans to do about healthcare is unclear.",exp:"Noun clauses use statement word order (subject + verb), not question inversion."},
      {id:"cx098",type:"error",q:"The school where I studied at has been demolished.",a:"The school where I studied has been demolished.",exp:"'Where' already means 'at which'. Adding 'at' is redundant. Alternatively: 'The school that I studied at'."},
      {id:"cx099",type:"error",q:"The evidence suggests, that the treatment is effective for most patients.",a:"The evidence suggests that the treatment is effective for most patients.",exp:"No comma should appear between a verb and its noun clause complement."},
      {id:"cx100",type:"error",q:"The student who work was outstanding received the highest award.",a:"The student whose work was outstanding received the highest award.",exp:"'Whose' is needed to show possession (the student's work), not 'who'."},
      {id:"cx101",type:"error",q:"Because the budget was limited was the reason the project was scaled back.",a:"The reason the project was scaled back was that the budget was limited.",exp:"'Because' and 'the reason' are both causal. Restructure to avoid redundancy."},
      {id:"cx102",type:"error",q:"The hospital, which it serves over ten thousand patients annually, is seeking additional funding.",a:"The hospital, which serves over ten thousand patients annually, is seeking additional funding.",exp:"'Which' replaces the subject in the relative clause. The pronoun 'it' is redundant."},
      {id:"cx103",type:"error",q:"Although many countries have signed the agreement, but few have met their targets.",a:"Although many countries have signed the agreement, few have met their targets.",exp:"'Although' and 'but' cannot be used together. Remove 'but'."},
      {id:"cx104",type:"error",q:"The organisation that whose mission is to reduce poverty has expanded globally.",a:"The organisation whose mission is to reduce poverty has expanded globally.",exp:"Use either 'that' or 'whose', not both. 'Whose' shows possession here."},
      {id:"cx105",type:"error",q:"If the population will continue to grow, resources will become scarcer.",a:"If the population continues to grow, resources will become scarcer.",exp:"In conditional clauses with 'if', use present simple for future reference, not 'will'."},
      {id:"cx106",type:"combine",q:"The government introduced a new tax. + The tax aims to reduce carbon emissions.",a:"The government introduced a new tax that aims to reduce carbon emissions.",exp:"'That' introduces a restrictive relative clause combining information about the tax."},
      {id:"cx107",type:"combine",q:"The policy was controversial. + The policy significantly reduced crime rates.",a:"Although the policy was controversial, it significantly reduced crime rates.",exp:"'Although' introduces a concession (adverbial clause) before the main point about reduced crime."},
      {id:"cx108",type:"combine",q:"The hospital has limited resources. + The hospital serves a large population.",a:"The hospital, which serves a large population, has limited resources.",exp:"'Which' introduces a non-restrictive relative clause adding information about the hospital."},
      {id:"cx109",type:"combine",q:"The professor published a groundbreaking study. + The professor specialises in environmental science.",a:"The professor who specialises in environmental science published a groundbreaking study.",exp:"'Who' introduces a restrictive relative clause identifying which professor."},
      {id:"cx110",type:"combine",q:"The economy will recover. + The government implements effective fiscal policies.",a:"The economy will recover if the government implements effective fiscal policies.",exp:"'If' introduces a conditional clause stating the requirement for economic recovery."},
      {id:"cx111",type:"combine",q:"The study was published. + Academic debate intensified.",a:"After the study was published, academic debate intensified.",exp:"'After' introduces a time clause showing the sequence of events."},
      {id:"cx112",type:"combine",q:"The city faces water shortages. + The city is located in an arid region.",a:"The city, which is located in an arid region, faces water shortages.",exp:"'Which' introduces a non-restrictive relative clause providing context about the city's location."},
      {id:"cx113",type:"combine",q:"The treatment was effective. + Many patients could not afford it.",a:"Although the treatment was effective, many patients could not afford it.",exp:"'Although' introduces a concession clause contrasting effectiveness with affordability."},
      {id:"cx114",type:"combine",q:"Researchers published their findings. + Other scientists could replicate the study.",a:"Researchers published their findings so that other scientists could replicate the study.",exp:"'So that' introduces a purpose clause explaining why the findings were published."},
      {id:"cx115",type:"combine",q:"The school hired a new principal. + The principal has twenty years of experience.",a:"The school hired a new principal who has twenty years of experience.",exp:"'Who' introduces a restrictive relative clause describing the principal."},
      {id:"cx116",type:"combine",q:"The technology was developed. + It transformed communication globally.",a:"The technology that was developed transformed communication globally.",exp:"'That' introduces a restrictive relative clause specifying which technology."},
      {id:"cx117",type:"combine",q:"Air quality improves. + Respiratory diseases will decline.",a:"When air quality improves, respiratory diseases will decline.",exp:"'When' introduces a time/condition clause about the circumstances for disease decline."},
      {id:"cx118",type:"combine",q:"The student worked extremely hard. + The student won the national scholarship.",a:"The student who worked extremely hard won the national scholarship.",exp:"'Who' introduces a restrictive relative clause identifying which student."},
      {id:"cx119",type:"combine",q:"The population is ageing rapidly. + Healthcare costs continue to rise.",a:"Because the population is ageing rapidly, healthcare costs continue to rise.",exp:"'Because' introduces a cause clause explaining why healthcare costs are rising."},
      {id:"cx120",type:"combine",q:"The factory was closed. + The factory had been polluting the river for years.",a:"The factory that had been polluting the river for years was closed.",exp:"'That' introduces a restrictive relative clause identifying which factory."},
      {id:"cx121",type:"combine",q:"The new curriculum is implemented effectively. + Student outcomes should improve.",a:"If the new curriculum is implemented effectively, student outcomes should improve.",exp:"'If' introduces a conditional clause stating the requirement for improved outcomes."},
      {id:"cx122",type:"combine",q:"The research was conducted over five years. + The research produced significant insights.",a:"The research that was conducted over five years produced significant insights.",exp:"'That' introduces a restrictive relative clause specifying which research."},
      {id:"cx123",type:"combine",q:"The charity provides meals to homeless people. + Its volunteers work around the clock.",a:"The charity, whose volunteers work around the clock, provides meals to homeless people.",exp:"'Whose' introduces a non-restrictive relative clause showing possession (the charity's volunteers)."},
      {id:"cx124",type:"combine",q:"Funding is secured. + The clinical trial will commence next month.",a:"Provided that funding is secured, the clinical trial will commence next month.",exp:"'Provided that' introduces a conditional clause specifying the requirement for the trial."},
      {id:"cx125",type:"combine",q:"The professor retired last year. + She had dedicated her career to cancer research.",a:"The professor, who had dedicated her career to cancer research, retired last year.",exp:"'Who' introduces a non-restrictive relative clause adding information about the professor."},
      {id:"cx126",type:"combine",q:"Many rural areas lack broadband access. + These areas have smaller populations.",a:"Many rural areas that have smaller populations lack broadband access.",exp:"'That' introduces a restrictive relative clause identifying which rural areas."},
      {id:"cx127",type:"combine",q:"The exam results were announced. + Students celebrated their achievements.",a:"After the exam results were announced, students celebrated their achievements.",exp:"'After' introduces a time clause showing the sequence."},
      {id:"cx128",type:"combine",q:"Climate targets must be met. + Future generations will suffer.",a:"Unless climate targets are met, future generations will suffer.",exp:"'Unless' (meaning 'if not') introduces the necessary condition to prevent suffering."},
      {id:"cx129",type:"combine",q:"The surgeon performed the operation. + The operation saved the patient's life.",a:"The operation that the surgeon performed saved the patient's life.",exp:"'That' introduces a restrictive relative clause identifying which operation."},
      {id:"cx130",type:"combine",q:"Many experts support the theory. + The theory suggests that early education yields lifelong benefits.",a:"Many experts support the theory that early education yields lifelong benefits.",exp:"'That' introduces an appositive/noun clause explaining the content of the theory."},
      {id:"cx131",type:"combine",q:"The region experienced severe drought. + Agricultural output declined sharply.",a:"Because the region experienced severe drought, agricultural output declined sharply.",exp:"'Because' introduces a cause clause linking drought to agricultural decline."},
      {id:"cx132",type:"combine",q:"The university has campuses in three cities. + Its main campus is in Sydney.",a:"The university, whose main campus is in Sydney, has campuses in three cities.",exp:"'Whose' introduces a non-restrictive relative clause showing possession."},
      {id:"cx133",type:"combine",q:"Students complete the required coursework. + They are eligible for the advanced programme.",a:"Students who complete the required coursework are eligible for the advanced programme.",exp:"'Who' introduces a restrictive relative clause identifying eligible students."},
      {id:"cx134",type:"combine",q:"The government was re-elected. + Living standards began to improve.",a:"After the government was re-elected, living standards began to improve.",exp:"'After' introduces a time clause showing the sequence."},
      {id:"cx135",type:"combine",q:"Healthcare is accessible to all citizens. + A society can be considered truly equitable.",a:"A society can be considered truly equitable only when healthcare is accessible to all citizens.",exp:"'When' introduces a condition/time clause specifying the requirement for equity."},
      {id:"cx136",type:"combine",q:"The policy has been criticised. + It has achieved measurable results.",a:"Even though the policy has been criticised, it has achieved measurable results.",exp:"'Even though' introduces a strong concession before stating the positive outcome."},
      {id:"cx137",type:"combine",q:"The scientist developed the vaccine. + The scientist won the Nobel Prize.",a:"The scientist who developed the vaccine won the Nobel Prize.",exp:"'Who' introduces a restrictive relative clause identifying which scientist."},
      {id:"cx138",type:"combine",q:"Public awareness increases. + Environmental protection will become a higher priority.",a:"As public awareness increases, environmental protection will become a higher priority.",exp:"'As' introduces a time clause showing gradual development."},
      {id:"cx139",type:"combine",q:"The conference attracted over two thousand delegates. + It was held in Melbourne.",a:"The conference, which was held in Melbourne, attracted over two thousand delegates.",exp:"'Which' introduces a non-restrictive relative clause adding information about the conference."},
      {id:"cx140",type:"combine",q:"The technology is widely adopted. + Productivity improvements will be significant.",a:"If the technology is widely adopted, productivity improvements will be significant.",exp:"'If' introduces a conditional clause about the requirement for productivity gains."},
      {id:"cx141",type:"transform",q:"The policy was effective. It was introduced by the new government. [Combine using a relative clause]",a:"The policy that was introduced by the new government was effective.",exp:"'That' introduces a restrictive relative clause identifying which policy. The clause is embedded within the main sentence."},
      {id:"cx142",type:"transform",q:"Education spending increased. Test scores improved. [Rewrite as a complex sentence showing cause]",a:"Because education spending increased, test scores improved.",exp:"'Because' introduces a cause clause, and the dependent clause comes first with a comma."},
      {id:"cx143",type:"transform",q:"The hospital was overcrowded. It still provided excellent care. [Rewrite using a concession clause]",a:"Although the hospital was overcrowded, it still provided excellent care.",exp:"'Although' introduces a concession clause, showing good care despite overcrowding."},
      {id:"cx144",type:"transform",q:"The professor is retiring. She has published over 100 papers. [Combine using a non-restrictive relative clause]",a:"The professor, who has published over 100 papers, is retiring.",exp:"'Who' introduces a non-restrictive relative clause (set off by commas) adding information about the professor."},
      {id:"cx145",type:"transform",q:"The programme reduced crime. The programme targeted at-risk youth. [Combine using a restrictive relative clause]",a:"The programme that targeted at-risk youth reduced crime.",exp:"'That' introduces a restrictive relative clause identifying which programme."},
      {id:"cx146",type:"transform",q:"People develop healthy habits early. They tend to live longer. [Rewrite as a complex sentence with a conditional clause]",a:"If people develop healthy habits early, they tend to live longer.",exp:"'If' introduces a conditional clause about the habit-longevity relationship."},
      {id:"cx147",type:"transform",q:"The reform was implemented. Public satisfaction increased dramatically. [Rewrite showing time sequence]",a:"After the reform was implemented, public satisfaction increased dramatically.",exp:"'After' introduces a time clause showing the sequence of events."},
      {id:"cx148",type:"transform",q:"The region has rich natural resources. The region's economy is still underdeveloped. [Combine using a concession clause]",a:"Although the region has rich natural resources, its economy is still underdeveloped.",exp:"'Although' introduces a concession showing underdevelopment despite resources."},
      {id:"cx149",type:"transform",q:"The school was founded in 1920. It has a long tradition of academic excellence. [Combine using a non-restrictive relative clause]",a:"The school, which was founded in 1920, has a long tradition of academic excellence.",exp:"'Which' introduces a non-restrictive relative clause adding historical information."},
      {id:"cx150",type:"transform",q:"The community invests in youth programmes. Crime rates will decrease. [Rewrite using a conditional clause]",a:"If the community invests in youth programmes, crime rates will decrease.",exp:"'If' introduces a conditional clause about investment and crime reduction."},
      {id:"cx151",type:"transform",q:"The study had a small sample size. Its findings were considered reliable. [Rewrite using a concession clause]",a:"Even though the study had a small sample size, its findings were considered reliable.",exp:"'Even though' introduces a strong concession about reliability despite the small sample."},
      {id:"cx152",type:"transform",q:"Dr. Patel conducted the research. Her work has been cited over 500 times. [Combine using a possessive relative clause]",a:"Dr. Patel, whose work has been cited over 500 times, conducted the research.",exp:"'Whose' introduces a non-restrictive possessive relative clause about Dr. Patel's citations."},
      {id:"cx153",type:"transform",q:"The government must act on climate change. Climate change threatens global food security. [Combine using a reason clause]",a:"The government must act on climate change because it threatens global food security.",exp:"'Because' introduces a reason clause explaining why action is needed."},
      {id:"cx154",type:"transform",q:"The new law was passed. Working conditions improved across the industry. [Rewrite showing time sequence]",a:"After the new law was passed, working conditions improved across the industry.",exp:"'After' introduces a time clause showing improvement following the law's passage."},
      {id:"cx155",type:"transform",q:"Education is underfunded. Public health outcomes will suffer. [Rewrite using a conditional clause]",a:"If education is underfunded, public health outcomes will suffer.",exp:"'If' introduces a conditional clause linking education funding to health outcomes."},
      {id:"cx156",type:"transform",q:"The charity raised millions of dollars. Its founder dedicated her life to humanitarian work. [Combine using a possessive relative clause]",a:"The charity, whose founder dedicated her life to humanitarian work, raised millions of dollars.",exp:"'Whose' introduces a non-restrictive possessive relative clause about the charity's founder."},
      {id:"cx157",type:"transform",q:"Emissions are not reduced significantly. Global temperatures will continue to rise. [Rewrite using 'unless']",a:"Unless emissions are reduced significantly, global temperatures will continue to rise.",exp:"'Unless' (meaning 'if not') introduces the condition needed to prevent temperature rises."},
      {id:"cx158",type:"transform",q:"The university offers generous scholarships. Many international students choose to enrol. [Rewrite showing cause]",a:"Because the university offers generous scholarships, many international students choose to enrol.",exp:"'Because' introduces a cause clause explaining why students enrol."},
      {id:"cx159",type:"transform",q:"The vaccine was developed. Millions of lives were saved. [Combine using a relative clause]",a:"The vaccine that was developed saved millions of lives.",exp:"'That' introduces a restrictive relative clause identifying the vaccine."},
      {id:"cx160",type:"transform",q:"Urbanisation continues. More green spaces need to be created. [Rewrite showing time/condition]",a:"As urbanisation continues, more green spaces need to be created.",exp:"'As' introduces a time clause showing the ongoing need alongside urbanisation."},
      {id:"cx161",type:"identify",q:"Because climate change threatens biodiversity, conservation efforts must be intensified.",a:"Complex sentence (adverbial clause of reason with 'because')",exp:"One independent clause + one dependent adverbial clause of reason = complex sentence."},
      {id:"cx162",type:"identify",q:"The policy that was introduced last year has reduced crime by 15 percent.",a:"Complex sentence (restrictive relative clause with 'that')",exp:"One independent clause containing a restrictive relative clause = complex sentence."},
      {id:"cx163",type:"identify",q:"What the researchers discovered has implications for public health policy.",a:"Complex sentence (noun clause as subject with 'what')",exp:"A noun clause ('what the researchers discovered') functions as the subject = complex sentence."},
      {id:"cx164",type:"identify",q:"The university, which was established in 1901, is one of the most respected in the country.",a:"Complex sentence (non-restrictive relative clause with 'which')",exp:"One independent clause + one non-restrictive relative clause = complex sentence."},
      {id:"cx165",type:"identify",q:"If the government invests in renewable energy, carbon emissions will decrease.",a:"Complex sentence (adverbial clause of condition with 'if')",exp:"One dependent conditional clause + one independent clause = complex sentence."},
      {id:"cx166",type:"identify",q:"Scientists believe that the ozone layer is gradually recovering.",a:"Complex sentence (noun clause as object with 'that')",exp:"One independent clause + one noun clause functioning as the object = complex sentence."},
      {id:"cx167",type:"identify",q:"Although the treatment was expensive, it produced remarkable results.",a:"Complex sentence (adverbial clause of concession with 'although')",exp:"One dependent concession clause + one independent clause = complex sentence."},
      {id:"cx168",type:"identify",q:"The student whose essay received the highest mark will represent the school.",a:"Complex sentence (possessive relative clause with 'whose')",exp:"One independent clause containing a possessive relative clause = complex sentence."},
      {id:"cx169",type:"identify",q:"Unless funding is increased, the research programme will be discontinued.",a:"Complex sentence (adverbial clause of condition with 'unless')",exp:"One dependent conditional clause + one independent clause = complex sentence."},
      {id:"cx170",type:"identify",q:"The region where deforestation has been most severe requires urgent intervention.",a:"Complex sentence (relative clause of place with 'where')",exp:"One independent clause containing a relative clause of place = complex sentence."}
    ]
  }

};
